import React from "react";
import { createRoot } from "react-dom/client";
import App from "./App";

createRoot(document.getElementById("root")).render(<App />);

if (screen.orientation?.lock) {
  screen.orientation.lock("landscape").catch(() => {});
}

import { useState, useCallback } from "react";
import { T, TECH_FONT, useCanvas, getCanvasTheme } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";


export default function CocrystalSim() {
  const [coformer, setCoformer] = useState("hmx"); // "hmx" | "fox7" | "tnt" | "dnb" | "none"
  const [molarRatio, setMolarRatio] = useState(1);
  const [particleSize, setParticleSize] = useState(50);

  const coformerData = {
    hmx:  { densityMod: -0.06, vodMod: -200, h50Mod: +41, fricMod: -40, name: "CL-20/HMX", color: T.cyan },
    fox7: { densityMod: -0.11, vodMod: -250, h50Mod: +31, fricMod: -68, name: "CL-20/FOX-7", color: T.green },
    tnt:  { densityMod: -0.26, vodMod: -800, h50Mod: +50, fricMod: -75, name: "CL-20/TNT", color: T.gold },
    dnb:  { densityMod: -0.20, vodMod: -600, h50Mod: +45, fricMod: -60, name: "CL-20/DNB", color: T.purple },
    none: { densityMod: 0, vodMod: 0, h50Mod: 0, fricMod: 0, name: "Pure CL-20", color: T.red },
  };

  const cd = coformerData[coformer];
  const ratioFactor = coformer === "none" ? 0 : 1 / molarRatio;

  const density = (2.04 + cd.densityMod * ratioFactor).toFixed(3);
  const rawVod = 9400 + cd.vodMod * ratioFactor;
  const vod = Math.round(rawVod);
  const impactH50 = 14 + cd.h50Mod * ratioFactor;
  const h50Adjusted = Math.round(impactH50 - (100 - particleSize) * 0.05);
  // P_CJ = density * VoD² / 4e6
  const pCj = ((parseFloat(density) * vod * vod) / 4e6).toFixed(1);

  const h50Color = h50Adjusted > 40 ? T.green : h50Adjusted > 25 ? T.orange : T.red;

  const canvasRef = useCanvas(
    (ctx, w, h, frameCount) => {
      const t = getCanvasTheme();
      const hw = w * 0.4; // 40% left, 60% right

      // Clear
      ctx.fillStyle = t.bg;
      ctx.fillRect(0, 0, w, h);

      // Separator
      ctx.strokeStyle = t.grid;
      ctx.beginPath();
      ctx.moveTo(hw, 0);
      ctx.lineTo(hw, h);
      ctx.stroke();

      // LEFT SIDE: Crystal Structure Schematic
      ctx.save();
      const gridSize = 6;
      const cellW = (hw - 20) / gridSize;
      const cellH = (h - 20) / gridSize;
      ctx.translate(10 + cellW / 2, 10 + cellH / 2);

      const ratio = Math.round(molarRatio);

      // Pass 1: Draw Hydrogen bond indicators (dashed lines)
      ctx.strokeStyle = t.dimText;
      ctx.setLineDash([2, 2]);
      ctx.lineWidth = 1;
      for (let i = 0; i < gridSize; i++) {
        for (let j = 0; j < gridSize; j++) {
          const idx = i * gridSize + j;
          const isCoformer = coformer !== "none" && idx % (ratio + 1) === ratio;
          if (isCoformer) {
            // Draw lines to adjacent cells
            const px = j * cellW;
            const py = i * cellH;
            if (j > 0) { ctx.beginPath(); ctx.moveTo(px, py); ctx.lineTo((j - 1) * cellW, py); ctx.stroke(); }
            if (i > 0) { ctx.beginPath(); ctx.moveTo(px, py); ctx.lineTo(j * cellW, (i - 1) * cellH); ctx.stroke(); }
          }
        }
      }
      ctx.setLineDash([]);

      // Pass 2: Draw Molecules
      for (let i = 0; i < gridSize; i++) {
        for (let j = 0; j < gridSize; j++) {
          const idx = i * gridSize + j;
          const isCoformer = coformer !== "none" && idx % (ratio + 1) === ratio;

          const px = j * cellW;
          const py = i * cellH;
          const pulse = isCoformer ? Math.sin(frameCount * 0.05 + idx) * 1.5 : 0;

          ctx.beginPath();
          ctx.arc(px, py, 6 + pulse, 0, Math.PI * 2);
          ctx.fillStyle = isCoformer ? cd.color : T.red;
          ctx.fill();
        }
      }
      // Label
      ctx.font = `bold 9px ${TECH_FONT}`;
      ctx.fillStyle = T.white;
      ctx.textAlign = "center";
      ctx.fillText(cd.name, (hw - 20) / 2, h - 25);
      ctx.restore();

      // RIGHT SIDE: Scatter Plot (Energy vs Safety)
      ctx.save();
      const rhw = w * 0.6;
      ctx.translate(hw, 0);

      const plotX = 30;
      const plotY = 20;
      const plotW = rhw - 40;
      const plotH = h - 40;

      // Axes
      ctx.strokeStyle = t.grid;
      ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(plotX, plotY + plotH); ctx.lineTo(plotX + plotW, plotY + plotH); ctx.stroke(); // X
      ctx.beginPath(); ctx.moveTo(plotX, plotY + plotH); ctx.lineTo(plotX, plotY); ctx.stroke(); // Y

      // Labels
      ctx.font = `10px ${TECH_FONT}`;
      ctx.fillStyle = t.dimText;
      ctx.textAlign = "center";
      ctx.fillText("IMPACT H50 (cm) → (SAFER)", plotX + plotW / 2, plotY + plotH + 15);
      ctx.save();
      ctx.translate(12, plotY + plotH / 2);
      ctx.rotate(-Math.PI / 2);
      ctx.fillText("VoD (m/s)  (ENERGY)", 0, 0);
      ctx.restore();

      // "Ideal Zone" Box in upper right (H50 > 30, VoD > 8500)
      const mapX = (h50) => plotX + ((Math.min(maxH50, Math.max(minH50, h50)) - minH50) / (maxH50 - minH50)) * plotW;
      const mapY = (v) => plotY + plotH - ((Math.min(maxVod, Math.max(minVod, v)) - minVod) / (maxVod - minVod)) * plotH;

      const minH50 = 10; const maxH50 = 80;
      const minVod = 6500; const maxVod = 9800;

      const idealX = mapX(30);
      const idealW = mapX(maxH50) - idealX;
      const idealY = mapY(maxVod);
      const idealH = mapY(8500) - idealY;

      ctx.fillStyle = `${T.green}10`;
      ctx.fillRect(idealX, idealY, idealW, idealH);
      ctx.strokeStyle = `${T.green}40`;
      ctx.strokeRect(idealX, idealY, idealW, idealH);

      // Reference Points
      const refs = [
        { name: "CL-20", h50: 14, vod: 9400, color: t.dimText },
        { name: "HMX", h50: 25, vod: 9100, color: t.dimText },
        { name: "RDX", h50: 28, vod: 8750, color: t.dimText },
        { name: "TNT", h50: 74, vod: 6900, color: t.dimText },
      ];

      refs.forEach((ref) => {
        const x = mapX(ref.h50);
        const y = mapY(ref.vod);
        ctx.beginPath(); ctx.arc(x, y, 3, 0, Math.PI * 2);
        ctx.fillStyle = ref.color; ctx.fill();
        ctx.font = `8px ${TECH_FONT}`;
        ctx.fillText(ref.name, x, y - 6);
      });

      // Current Cocrystal Point
      const cx = mapX(h50Adjusted);
      const cy = mapY(vod);
      ctx.beginPath();
      ctx.arc(cx, cy, 5 + Math.sin(frameCount * 0.1) * 2, 0, Math.PI * 2);
      ctx.fillStyle = h50Color;
      ctx.fill();
      ctx.strokeStyle = t.bg;
      ctx.stroke();

      ctx.font = `bold 10px ${TECH_FONT}`;
      ctx.fillStyle = T.white;
      // offset label to avoid overlapping with dot
      ctx.fillText("CURRENT", cx, cy + 12);

      ctx.restore();

    },
    [coformer, molarRatio, particleSize, cd, vod, h50Adjusted, h50Color],
    { animate: true }, // animate for crystal pulses
  );

  const buildPrompt = useCallback(
    () =>
      `Energetic cocrystal engineering simulation — current parameters:
ROLE: "You are an expert in energetic materials, cocrystal engineering, and insensitive munitions (IM) design. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Base explosive: CL-20
2. Coformer: ${coformer === "none" ? "None" : coformer.toUpperCase()}
3. Molar ratio (CL-20 : Coformer): ${molarRatio}:1
4. Particle size: ${particleSize} μm
5. Computed Density: ${density} g/cm³
6. Detonation Velocity (VoD): ${vod} m/s
7. Impact Sensitivity (H50): ${h50Adjusted} cm
8. Detonation Pressure (P_CJ): ${pCj} GPa

ANALYSIS REQUEST:
Part 1 — MATERIAL PROPERTIES: Analyze this cocrystal formulation. What trade-offs between energy and safety are observed compared to pure CL-20?
Part 2 — SENSITIVITY: How does the coformer affect the intermolecular hydrogen bonding and packing density to alter the sensitivity?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this development relate to insensitive munitions (IM) programs at HEMRL Pune? What role could this play in future advanced warheads (like for BrahMos or Agni)?`,
    [coformer, molarRatio, particleSize, density, vod, h50Adjusted, pCj],
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={180} maxWidth={460} />
      <PillRow>
        <Pill active={coformer === "hmx"} onClick={() => setCoformer("hmx")} color={T.cyan}>HMX</Pill>
        <Pill active={coformer === "fox7"} onClick={() => setCoformer("fox7")} color={T.green}>FOX-7</Pill>
        <Pill active={coformer === "tnt"} onClick={() => setCoformer("tnt")} color={T.gold}>TNT</Pill>
        <Pill active={coformer === "dnb"} onClick={() => setCoformer("dnb")} color={T.purple}>DNB</Pill>
        <Pill active={coformer === "none"} onClick={() => setCoformer("none")} color={T.red}>None</Pill>
      </PillRow>
      <Slider disabled={coformer === "none"} label="Molar Ratio (CL-20 : Coformer)" value={molarRatio} onChange={setMolarRatio} min={1} max={8} step={1} unit=":1" color={T.accent} />
      <Slider label="Particle Size" value={particleSize} onChange={setParticleSize} min={1} max={100} step={1} unit=" μm" color={T.cyan} />
      <DataRow>
        <DataBox label="VoD" value={vod} unit="m/s" color={T.red} />
        <DataBox label="Density" value={density} unit="g/cm³" color={T.purple} />
        <DataBox label="H50" value={h50Adjusted} unit="cm" color={h50Color} />
        <DataBox label="P_CJ" value={pCj} unit="GPa" color={T.orange} />
      </DataRow>
      <InfoBox color={T.purple}>
        <strong style={{ color: T.purple }}>Energetic cocrystals</strong> are the frontier of HEM research. CL-20/HMX cocrystals (Bolton 2012) retain 95% of CL-20's energy while doubling impact safety. HEMRL Pune leads India's CL-20 synthesis program. FOX-7 cocrystals achieve 64% reduction in impact sensitivity — promising for insensitive munitions (IM) compliance.
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.purple} />
      <ExportBtn simId="cocrystal" getData={() => ({ coformer, molarRatio, particleSize, density, vod, h50: h50Adjusted, pCj })} color={T.purple} />
    </div>
  );
}

import { useState, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme } from "../utils";
import {
  Pill,
  Slider,
  DataBox,
  InfoBox,
  PillRow,
  DataRow,
  SimCanvas,
  AIInsight,
  ExportBtn,
} from "../components";

export default function CombustionInstabilitySim() {
  const [motorLength, setMotorLength] = useState(1.5);
  const [motorDia, setMotorDia] = useState(0.5);
  const [chamberP, setChamberP] = useState(8);
  const [propellant, setPropellant] = useState("htpb_ap");
  const [dampingMethod, setDampingMethod] = useState("none");

  const speedOfSound = 1000 + chamberP * 30;
  const f1L = speedOfSound / (2 * motorLength);
  const f2L = 2 * f1L;
  const f1T = 1.84 * speedOfSound / (Math.PI * motorDia);

  const nIndex = { htpb_ap_al: 0.35, htpb_ap: 0.45, db: 0.55 }[propellant];
  const responseFunc = nIndex / (1 - nIndex);
  const dampFactor = { none: 1.0, baffles: 0.4, acoustic_liner: 0.3, resonance_rod: 0.5 }[dampingMethod];

  const gain = responseFunc * (1 + chamberP * 0.02);
  const loss = (1 / (motorLength * motorDia)) * 0.5 / dampFactor;
  const stabilityMargin = ((loss - gain) / loss * 100);

  const oscAmplitude = stabilityMargin < 0 ? Math.min(30, Math.abs(stabilityMargin) * 0.5) : 0;

  const riskLevel = stabilityMargin > 20 ? "STABLE" : stabilityMargin > 0 ? "MARGINAL" : "UNSTABLE";
  const riskColor = stabilityMargin > 20 ? T.green : stabilityMargin > 0 ? T.orange : T.red;

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const theme = getCanvasTheme();
      ctx.fillStyle = theme.canvasBackground;
      ctx.fillRect(0, 0, W, H);

      const topH = H * 0.6;
      const botH = H * 0.4;

      const mPadL = 20, mPadR = 40;
      const mW = W - mPadL - mPadR;
      const mH = Math.max(20, Math.min(topH - 20, motorDia * 40));
      const mY = (topH - mH) / 2;

      ctx.strokeStyle = T.dimText;
      ctx.lineWidth = 2;
      ctx.strokeRect(mPadL, mY, mW, mH);

      const pColor = { htpb_ap_al: "#8B8B83", htpb_ap: "#A0522D", db: "#CD853F" }[propellant];

      ctx.fillStyle = pColor;
      ctx.globalAlpha = 0.8;
      ctx.fillRect(mPadL, mY, mW, mH * 0.3);
      ctx.fillRect(mPadL, mY + mH * 0.7, mW, mH * 0.3);
      ctx.globalAlpha = 1;

      ctx.beginPath();
      ctx.moveTo(mPadL + mW, mY);
      ctx.lineTo(mPadL + mW + 20, mY - 10);
      ctx.lineTo(mPadL + mW + 20, mY + mH + 10);
      ctx.lineTo(mPadL + mW, mY + mH);
      ctx.fillStyle = "#333";
      ctx.fill();

      ctx.strokeStyle = T.cyan;
      ctx.lineWidth = 2;
      if (dampingMethod === "baffles") {
        const x1 = mPadL + mW * 0.33;
        const x2 = mPadL + mW * 0.67;
        ctx.beginPath();
        ctx.moveTo(x1, mY); ctx.lineTo(x1, mY + mH * 0.45);
        ctx.moveTo(x2, mY); ctx.lineTo(x2, mY + mH * 0.45);
        ctx.moveTo(x1, mY + mH); ctx.lineTo(x1, mY + mH * 0.55);
        ctx.moveTo(x2, mY + mH); ctx.lineTo(x2, mY + mH * 0.55);
        ctx.stroke();
      } else if (dampingMethod === "acoustic_liner") {
        ctx.strokeStyle = `${T.cyan}80`;
        ctx.setLineDash([2, 2]);
        ctx.strokeRect(mPadL + 2, mY + 2, mW - 4, mH - 4);
        ctx.setLineDash([]);
      } else if (dampingMethod === "resonance_rod") {
        ctx.fillStyle = T.cyan;
        ctx.fillRect(mPadL, mY + mH * 0.45, mW * 0.8, mH * 0.1);
      }

      const timeSec = frame * 0.016; 
      const displayAmp = stabilityMargin > 0 ? Math.max(1, 10 * Math.exp(-timeSec * 0.5)) : (5 + oscAmplitude * Math.min(1, timeSec * 0.5) * 0.5);

      const boreY = mY + mH * 0.5;

      ctx.beginPath();
      ctx.strokeStyle = riskColor;
      ctx.lineWidth = stabilityMargin < 0 ? 2 : 1;
      for(let x = 0; x <= mW; x += 2) {
        const phase = (x / mW) * Math.PI;
        const waveY = boreY + Math.sin(phase) * Math.cos(timeSec * 10) * displayAmp;
        x === 0 ? ctx.moveTo(mPadL + x, waveY) : ctx.lineTo(mPadL + x, waveY);
      }
      ctx.stroke();

      ctx.beginPath();
      ctx.strokeStyle = `${riskColor}50`;
      ctx.lineWidth = 1;
      for(let x = 0; x <= mW; x += 2) {
        const phase = (x / mW) * Math.PI * 2;
        const waveY = boreY + Math.sin(phase) * Math.cos(timeSec * 20) * (displayAmp * 0.5);
        x === 0 ? ctx.moveTo(mPadL + x, waveY) : ctx.lineTo(mPadL + x, waveY);
      }
      ctx.stroke();

      const stripY = topH;
      ctx.fillStyle = `${theme.canvasSurface}`;
      ctx.fillRect(0, stripY, W, botH);
      ctx.strokeStyle = `rgba(255,255,255,0.1)`;
      ctx.beginPath();
      ctx.moveTo(0, stripY);
      ctx.lineTo(W, stripY);
      ctx.stroke();

      ctx.fillStyle = T.dimText;
      ctx.font = `600 7px ${TECH_FONT}`;
      ctx.textAlign = "left";
      ctx.fillText("GAIN (red) vs LOSS (green) vs FREQUENCY", 5, stripY + 12);

      const maxF = f1T * 1.2;
      const pad = 15;
      const bW = W - pad * 2;
      const bH = botH - 20;
      const bY = stripY + 15;

      const normG = Math.max(0, gain * 20);
      const normL = Math.max(0, loss * 20);

      ctx.fillStyle = gain > loss ? `${T.red}20` : `${T.green}20`;
      ctx.fillRect(pad, bY, bW, bH);

      ctx.beginPath(); ctx.strokeStyle = T.red; ctx.lineWidth = 2;
      ctx.moveTo(pad, Math.max(bY, bY + bH - normG - 5));
      ctx.lineTo(pad + bW, Math.max(bY, bY + bH - normG * 0.5 - 5));
      ctx.stroke();

      ctx.beginPath(); ctx.strokeStyle = T.green; ctx.lineWidth = 2;
      ctx.moveTo(pad, Math.max(bY, bY + bH - normL));
      ctx.lineTo(pad + bW, Math.max(bY, bY + bH - normL));
      ctx.stroke();

      const markFreq = (f, col, lbl) => {
        if(f > maxF) return;
        const px = pad + (f / maxF) * bW;
        ctx.strokeStyle = col;
        ctx.setLineDash([2, 5]);
        ctx.beginPath();
        ctx.moveTo(px, bY);
        ctx.lineTo(px, bY + bH);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.fillStyle = col;
        ctx.textAlign = "center";
        ctx.font = `800 8px ${MONO_FONT}`;
        ctx.fillText(lbl, px, bY + bH + 8);
      };

      markFreq(f1L, T.cyan, "f1L");
      markFreq(f2L, `${T.cyan}80`, "f2L");
      markFreq(f1T, T.purple, "f1T");

    },
    [motorLength, motorDia, chamberP, propellant, dampingMethod, f1L, f2L, f1T, gain, loss, stabilityMargin, oscAmplitude, riskColor],
    { animate: true },
  );

  const buildPrompt = useCallback(
    () =>
      `Solid rocket motor combustion instability and acoustic stability analysis — current parameters:
ROLE: "You are an expert in solid propulsion and acoustic instability analysis. You have deep knowledge of DRDO, HEMRL, and ISRO programs."

PARAMETERS (numbered):
1. Motor length: ${motorLength} m
2. Motor diameter: ${motorDia} m
3. Chamber pressure: ${chamberP} MPa
4. Propellant type: ${propellant.toUpperCase()} (burn rate exponent n=${nIndex})
5. Damping method: ${dampingMethod.toUpperCase()}
6. First longitudinal mode (f1L): ${f1L.toFixed(0)} Hz
7. First tangential mode (f1T): ${f1T.toFixed(0)} Hz
8. Calculated Stability Margin: ${stabilityMargin.toFixed(1)}%
9. Oscillation Amplitude Prediction: ${oscAmplitude > 0 ? oscAmplitude.toFixed(1) + "% of Pc" : "Stable (0%)"}

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 — SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL/ISRO programs? Reference specific Indian systems (e.g., Agni, PSLV, GSLV, Pinaka, SMART, Astra) where applicable. What are India's current capabilities and gaps in this domain?`,
    [motorLength, motorDia, chamberP, propellant, nIndex, dampingMethod, f1L, f1T, stabilityMargin, oscAmplitude],
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={420} height={200} maxWidth={420} />
      <PillRow>
        <Pill active={propellant === "htpb_ap_al"} onClick={() => setPropellant("htpb_ap_al")} color={T.accent}>HTPB/AP/Al</Pill>
        <Pill active={propellant === "htpb_ap"} onClick={() => setPropellant("htpb_ap")} color={T.orange}>HTPB/AP</Pill>
        <Pill active={propellant === "db"} onClick={() => setPropellant("db")} color={T.gold}>Double-Base</Pill>
      </PillRow>
      <PillRow>
        <Pill active={dampingMethod === "none"} onClick={() => setDampingMethod("none")} color={T.red}>No Damping</Pill>
        <Pill active={dampingMethod === "baffles"} onClick={() => setDampingMethod("baffles")} color={T.cyan}>Baffles</Pill>
        <Pill active={dampingMethod === "acoustic_liner"} onClick={() => setDampingMethod("acoustic_liner")} color={T.green}>Acoustic Liner</Pill>
        <Pill active={dampingMethod === "resonance_rod"} onClick={() => setDampingMethod("resonance_rod")} color={T.purple}>Resonance Rod</Pill>
      </PillRow>
      <Slider label="Motor Length" value={motorLength} onChange={setMotorLength} min={0.5} max={3.0} step={0.1} unit=" m" color={T.orange} />
      <Slider label="Motor Diameter" value={motorDia} onChange={setMotorDia} min={0.2} max={1.0} step={0.05} unit=" m" color={T.gold} />
      <Slider label="Chamber Pressure" value={chamberP} onChange={setChamberP} min={3} max={15} step={0.5} unit=" MPa" color={T.red} />

      <DataRow>
        <DataBox label="f1L" value={f1L.toFixed(0)} unit="Hz" color={T.cyan} />
        <DataBox label="f1T" value={f1T.toFixed(0)} unit="Hz" color={T.purple} />
        <DataBox label="Margin" value={stabilityMargin.toFixed(0)} unit="%" color={riskColor} />
        <DataBox label="Osc." value={oscAmplitude.toFixed(1)} unit="%" color={riskColor} />
        <DataBox label="n" value={nIndex} unit="" color={T.gold} />
      </DataRow>

      <div style={{ textAlign: "center", fontSize: 12, fontWeight: 700, color: riskColor, fontFamily: TECH_FONT, marginTop: 10 }}>
        {riskLevel === "UNSTABLE" ? "⚠ COMBUSTION INSTABILITY PREDICTED" :
         riskLevel === "MARGINAL" ? "⚡ MARGINAL STABILITY — ADD DAMPING" :
         "✓ MOTOR IS STABLE"}
      </div>

      <InfoBox>
        Combustion instability occurs when acoustic modes couple with pressure-dependent burn rate (Pc^n). The burn rate exponent 'n' is critical — higher n means stronger coupling. Session 5A (HEMCE 2026) covers mitigation strategies including baffles, acoustic liners, and inert particle damping. ISRO's PSLV and Agni motors use baffles for longitudinal mode suppression.
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.orange} />
      <ExportBtn
        simId="instability"
        getData={() => ({ motorLength, motorDia, chamberP, propellant, dampingMethod, f1L, f1T, stabilityMargin, oscAmplitude })}
        color={T.orange}
      />
    </div>
  );
}

import { useState, useRef, useMemo } from "react";
import { useCanvas, T, prng, getCanvasTheme } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ActionBtn } from "../components";
import { AIInsight } from "../components/AIInsight";

export function CookOffTestSim() {
  const [phase, setPhase] = useState("idle"); // idle | heating | reaction
  const [munType, setMunType] = useState("standard");
  const [explosive, setExplosive] = useState("tnt");
  const [confinement, setConfinement] = useState("heavy");
  const [heatRate, setHeatRate] = useState(3);

  const tempRef = useRef(20);

  const cookoffData = {
     tnt: { melt: 81, decomp: 240, detTemp: 300, sensitivity: "low", color: "#eab308" },
     rdx: { melt: 205, decomp: 230, detTemp: 260, sensitivity: "medium", color: "#ef4444" },
     hmx: { melt: 280, decomp: 290, detTemp: 310, sensitivity: "medium", color: "#a855f7" },
     pbx: { melt: 190, decomp: 350, detTemp: 400, sensitivity: "low", color: "#3b82f6" }, 
  };
  const ed = cookoffData[explosive];

  // Insensitive munition modifier
  const imFactor = munType === "insensitive" ? 1.4 : 1.0; 

  // Response type based on confinement + heat rate
  const responseType = confinement === "heavy" && heatRate > 10 ? "DETONATION" :
                       confinement === "heavy" ? "DEFLAGRATION" :
                       confinement === "light" ? "BURN" : "BURN";

  // Time to event: t = (detTemp * imFactor - 20) / heatRate (minutes)
  const timeToEvent = ((ed.detTemp * imFactor - 20) / heatRate).toFixed(0);

  // Violence level (1-5 scale)
  const violence = confinement === "heavy" ? 5 :
                   confinement === "light" ? 3 : 1;

  // Thresholds
  const tMelt = ed.melt;
  const tDecomp = ed.decomp * imFactor;
  const tDet = ed.detTemp * imFactor;

  const canvasRef = useCanvas(
    (ctx, W, H, frameCount) => {
      const theme = getCanvasTheme();
      ctx.fillStyle = theme.canvasBackground;
      ctx.fillRect(0, 0, W, H);

      // Heating simulation logic
      if (phase === "heating") {
        const ramp = Math.max(0.5, heatRate * 0.15); 
        tempRef.current += ramp;
        if (tempRef.current >= tDet) {
          tempRef.current = tDet;
          setPhase("reaction");
        }
      }

      const t = tempRef.current;

      // Determine visual state
      const isMelting = t >= tMelt && t < tDecomp;
      const isDecomp = t >= tDecomp && t < tDet;
      const isReacting = phase === "reaction";

      // Draw the heat source / environment below
      if (t > 20 || phase !== "idle") {
        if (heatRate > 10) {
           // Fast cook-off flames
           const fireInt = Math.min((t - 20) / (tDet - 20), 1);
           const fGrad = ctx.createLinearGradient(0, W/2, 0, H);
           fGrad.addColorStop(0, `rgba(255, 100, 0, 0)`);
           fGrad.addColorStop(1, `rgba(255, 50, 0, ${fireInt * 0.8})`);
           ctx.fillStyle = fGrad;
           ctx.beginPath();
           for(let i=0; i<20; i++) {
              let fHeight = 60 + Math.sin(frameCount * 0.1 + i) * 20 * fireInt;
              ctx.moveTo(i * (W/20), H);
              ctx.lineTo(i * (W/20) + (W/40), H - fHeight);
              ctx.lineTo((i+1) * (W/20), H);
           }
           ctx.fill();
        } else {
           // Slow cook-off gradient
           const fireInt = Math.min((t - 20) / (tDet - 20), 1);
           const slowGrad = ctx.createLinearGradient(0, H - 40, 0, H);
           slowGrad.addColorStop(0, "transparent");
           slowGrad.addColorStop(1, `rgba(255, 100, 0, ${fireInt * 0.5})`);
           ctx.fillStyle = slowGrad;
           ctx.fillRect(0, H - 40, W, 40);
        }
      }

      // Draw Munition Cross-Section
      const cx = W / 2;
      const cy = H / 2 - 10;
      const mWidth = 160;
      const mHeight = 60;
      const casingThick = confinement === "heavy" ? 10 : confinement === "light" ? 4 : 1;

      if (!isReacting || responseType !== "DETONATION") {
        // Casing
        ctx.fillStyle = confinement === "unconfined" ? "transparent" : T.gray;
        ctx.fillRect(cx - mWidth/2 - casingThick, cy - mHeight/2 - casingThick, mWidth + casingThick*2, mHeight + casingThick*2);

        ctx.fillStyle = "#333";
        ctx.fillRect(cx - mWidth/2 - casingThick, cy - mHeight/2 - casingThick, casingThick, mHeight + casingThick*2);

        // Nose 
        if (confinement !== "unconfined") {
           ctx.beginPath();
           ctx.moveTo(cx + mWidth/2 + casingThick, cy - mHeight/2 - casingThick);
           ctx.lineTo(cx + mWidth/2 + casingThick + 40, cy);
           ctx.lineTo(cx + mWidth/2 + casingThick, cy + mHeight/2 + casingThick);
           ctx.fill();
        }

        // Inner explosive core
        let coreColor = ed.color;
        // Temperature gradient overlay (blue->yellow->orange->red)
        const tempRatio = Math.min(1, (t - 20) / (tDet - 20));

        ctx.fillStyle = coreColor;
        ctx.fillRect(cx - mWidth/2, cy - mHeight/2, mWidth, mHeight);

        // Overlay heating color
        ctx.fillStyle = tempRatio < 0.5 ? `rgba(234, 179, 8, ${tempRatio * 1.5})` : `rgba(239, 68, 68, ${tempRatio})`;
        ctx.fillRect(cx - mWidth/2, cy - mHeight/2, mWidth, mHeight);

        // Physics Animations
        if (isMelting) {
           ctx.fillStyle = coreColor;
           for(let i=0; i<5; i++) {
              let dripY = cy + mHeight/2 + (frameCount * 0.5 + i*15) % 20;
              ctx.beginPath();
              ctx.arc(cx - mWidth/4 + i*25, dripY, 3, 0, Math.PI*2);
              ctx.fill();
           }
        }

        if (isDecomp) {
           ctx.fillStyle = "rgba(100, 255, 100, 0.6)";
           for(let i=0; i<15; i++) {
              let bx = cx - mWidth/2 + 10 + prng(frameCount, i*3)*mWidth*0.9;
              let by = cy - mHeight/2 + 10 + prng(frameCount, i*3+1)*(mHeight - 20);
              ctx.beginPath();
              ctx.arc(bx, by, prng(frameCount, i*3+2)*3+1, 0, Math.PI*2);
              ctx.fill();
           }
        }
      }

      // Reaction
      if (isReacting) {
        if (responseType === "DETONATION") {
          // Flash + Blast
          ctx.fillStyle = `rgba(255, 200, 50, 0.9)`;
          ctx.beginPath();
          for (let i = 0; i < 20; i++) {
            const r = prng(frameCount, i * 3) * 200 + 50;
            const a = prng(frameCount, i * 3 + 1) * Math.PI * 2;
            ctx.lineTo(cx + Math.cos(a) * r, cy + Math.sin(a) * r);
          }
          ctx.closePath();
          ctx.fill();

          // Shockwave
          ctx.strokeStyle = "rgba(255,255,255,0.5)";
          ctx.lineWidth = 4;
          ctx.beginPath();
          ctx.arc(cx, cy, (frameCount % 30) * 10, 0, Math.PI*2);
          ctx.stroke();

        } else if (responseType === "DEFLAGRATION") {
          // Violent fire breaking casing
          ctx.fillStyle = `rgba(255, 150, 50, 0.9)`;
          for (let i = 0; i < 15; i++) {
             ctx.beginPath();
             ctx.arc(cx + (prng(frameCount, i*4) * 160 - 80), cy - prng(frameCount, i*4+1) * 60, prng(frameCount, i*4+2) * 30 + 10, 0, Math.PI * 2);
             ctx.fill();
          }
          // Broken casing parts
          ctx.fillStyle = T.gray;
          ctx.fillRect(cx - 50, cy + 40, 30, casingThick);
          ctx.fillRect(cx + 40, cy + 50, 40, casingThick);

        } else {
          // Burn
          ctx.fillStyle = `rgba(100, 150, 255, 0.8)`;
          for (let i = 0; i < 10; i++) {
             ctx.beginPath();
             ctx.arc(cx + (prng(frameCount, i*4) * 100 - 50), cy - 20 - prng(frameCount, i*4+1) * 40, prng(frameCount, i*4+2) * 20 + 10, 0, Math.PI * 2);
             ctx.fill();
          }
        }
      }

      // Vertical Thermometer
      const barX = W - 30;
      const barY = 20;
      const barH = H - 40;

      // Thermometer BG
      ctx.fillStyle = "#1e293b";
      ctx.fillRect(barX, barY, 15, barH);

      // Thermometer Fill
      const maxT = 500;
      const fillRatio = Math.min(1, t / maxT);
      const fillH = fillRatio * barH;
      const thermColor = t > tDet ? T.red : t > tDecomp ? T.orange : t > tMelt ? T.gold : T.cyan;
      ctx.fillStyle = thermColor;
      ctx.fillRect(barX, barY + barH - fillH, 15, fillH);

      // Phase Labels
      ctx.fillStyle = T.white;
      ctx.font = `800 12px monospace`;
      ctx.textAlign = "center";
      const phaseLabel = isReacting ? "REACTION" :
                         isDecomp ? "DECOMPOSITION" :
                         isMelting ? "MELT" : "SOLID";

      if (!isReacting) {
        ctx.fillText(`${Math.floor(t)}°C`, barX + 7, barY - 5);
      }
      ctx.font = `800 16px monospace`;
      ctx.fillStyle = thermColor;
      ctx.fillText(phaseLabel, cx, 30);
      ctx.textAlign = "left";

    },
    [phase, munType, explosive, confinement, heatRate, tMelt, tDecomp, tDet, responseType, ed],
    { animate: true },
  );

  const startTest = () => {
    tempRef.current = 20;
    setPhase("heating");
  };

  const reset = () => {
    tempRef.current = 20;
    setPhase("idle");
  };

  const vColor = violence > 3 ? T.red : violence === 3 ? T.orange : T.green;

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={200} />

      <PillRow>
        <Pill active={munType === "standard"} onClick={() => { setMunType("standard"); reset(); }} color={T.red}>
          Std Munition
        </Pill>
        <Pill active={munType === "insensitive"} onClick={() => { setMunType("insensitive"); reset(); }} color="#3b82f6">
          IM Modifier (+40%)
        </Pill>
      </PillRow>

      <PillRow>
        <Pill active={explosive === "tnt"} onClick={() => { setExplosive("tnt"); reset(); }} color={T.gold}>TNT</Pill>
        <Pill active={explosive === "rdx"} onClick={() => { setExplosive("rdx"); reset(); }} color={T.red}>RDX</Pill>
        <Pill active={explosive === "hmx"} onClick={() => { setExplosive("hmx"); reset(); }} color={T.purple}>HMX</Pill>
        <Pill active={explosive === "pbx"} onClick={() => { setExplosive("pbx"); reset(); }} color={T.cyan}>PBX (IM)</Pill>
      </PillRow>

      <PillRow>
        <Pill active={confinement === "unconfined"} onClick={() => { setConfinement("unconfined"); reset(); }} color={T.gray}>Unconfined</Pill>
        <Pill active={confinement === "light"} onClick={() => { setConfinement("light"); reset(); }} color={T.cyan}>Light</Pill>
        <Pill active={confinement === "heavy"} onClick={() => { setConfinement("heavy"); reset(); }} color={T.red}>Heavy Cas.</Pill>
      </PillRow>

      <Slider label="Heating Rate" value={heatRate} onChange={(v) => { setHeatRate(v); reset(); }} min={1} max={20} unit="°C/min" color={T.orange} />

      <DataRow>
        <DataBox label="T_melt" value={tMelt.toFixed(0)} unit="°C" color={T.gold} />
        <DataBox label="T_decomp" value={tDecomp.toFixed(0)} unit="°C" color={T.orange} />
        <DataBox label="T_det" value={tDet.toFixed(0)} unit="°C" color={T.red} />
      </DataRow>
      <DataRow style={{marginTop: 8}}>
        <DataBox label="Time" value={timeToEvent} unit="min" color={T.cyan} />
        <DataBox label="Response" value={responseType} unit="" color={vColor} />
        <DataBox label="Violence" value={`${violence}/5`} unit="" color={vColor} />
      </DataRow>

      <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
        <ActionBtn onClick={startTest} disabled={phase !== "idle"} color={T.orange}>
          {phase === "heating" ? "HEATING..." : phase === "reaction" ? "TEST COMPLETED" : "INITIATE COOK-OFF TEST"}
        </ActionBtn>
      </div>

      <InfoBox color={munType === "insensitive" ? "#3b82f6" : T.accent}>
        Cook-off testing (MIL-STD-2105D) evaluates explosive response to thermal stimulus. Slow cook-off (3°C/min) simulates fire exposure; fast cook-off (&gt;10°C/min) simulates adjacent detonation heating. Insensitive Munitions (IM) must pass with burn-only response (no detonation). HEMRL tests all Indian warhead fills per STANAG 4240. Paper FA11-P05 at HEMCE 2026 presents slow cook-off in metallic casings.
      </InfoBox>

      <AIInsight
        buildPrompt={() => `Focus domain: insensitive munitions and cook-off thermal response testing.
Context: Analyzing cook-off test with ${explosive.toUpperCase()} in ${confinement} confinement at ${heatRate}°C/min. 
Behavior observed: ${responseType} response.
1. Provide a technical analysis of this cook-off outcome per MIL-STD-2105D.
2. What are the specific thermal decomposition mechanisms leading to this violence level?
3. Mention FA11-P05 from HEMCE 2026, which studies slow cook-off in metallic casings, and relate it to HEMRL/India's IM requirements.
`}
        color={T.cyan}
      />
    </div>
  );
}

export default CookOffTestSim;

import { useState, useRef, useEffect, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ActionBtn, ResetBtn, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";

import { MISSILE_DB } from "../data/missileDB";

export default function DetonationSim() {
  const related = MISSILE_DB.filter((m) => m.relatedSimId === "detonation");
  const [running, setRunning] = useState(false);
  const [time, setTime] = useState(0);
  const [charge, setCharge] = useState(5);
  const [distance, setDistance] = useState(20);
  const [heMat, setHeMat] = useState("tnt");
  const [barrier, setBarrier] = useState("none"); // "none" | "sandbag" | "concrete" | "aqueous_foam" | "composite"
  const [application, setApplication] = useState("openfield"); // "openfield" | "shaped_charge" | "efp" | "mining" | "demolition"
  const animRef = useRef(null);
  const vod = { tnt: 6900, rdx: 8750, cl20: 9380, hmx: 9100 }[heMat];
  const reF = { tnt: 1.0, rdx: 1.6, cl20: 2.0, hmx: 1.7 }[heMat];
  const tntEq = (charge * reF).toFixed(1);
  const scaledDist = distance / Math.pow(Number(tntEq), 1 / 3);
  const logZ = Math.log10(Number(scaledDist));
  let peakOP = Math.pow(10, 2.78 - 1.6 * logZ - 0.198 * logZ * logZ);
  if (scaledDist < 0.5) peakOP = 500;
  if (scaledDist > 40) peakOP = 0.001;

  const appData = {
    openfield: { factor: 1.0, desc: "Unconfined detonation — standard Kingery-Bulmash" },
    shaped_charge: { factor: 0.3, desc: "Energy focused into jet — 70% less blast, high penetration" },
    efp: { factor: 0.5, desc: "Explosively Formed Penetrator — moderate blast + projectile" },
    mining: { factor: 1.2, desc: "Confined blast — 20% amplification from rock reflection" },
    demolition: { factor: 0.8, desc: "Controlled demo — shaped charges reduce collateral blast" },
  };

  peakOP = peakOP * appData[application].factor;
  const peakOPDisplay = peakOP.toFixed(2);
  const attenuation = { none: 1.0, sandbag: 0.55, concrete: 0.30, aqueous_foam: 0.40, composite: 0.20 };
  const mitigatedOP = (Number(peakOP) * attenuation[barrier]).toFixed(2);
  const impulse = (((0.067 * Math.pow(Number(tntEq), 2 / 3)) / distance) * 1000).toFixed(0);
  const arrivalMs = ((distance / (340 + peakOP * 100)) * 1000).toFixed(0);
  const progress = Math.min(time / 2, 1);

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const cy = H / 2,
        cx = 60;
      const theme = getCanvasTheme();

      const bgGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, W);
      bgGrad.addColorStop(0, theme.canvasBackground);
      bgGrad.addColorStop(1, theme.canvasSurface);
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, W, H);

      ctx.strokeStyle = "rgba(255,255,255,0.05)";
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(0, H - 20);
      ctx.lineTo(W, H - 20);
      ctx.stroke();

      const chargeColor = { tnt: T.orange, rdx: T.gold, cl20: T.red, hmx: T.accent }[heMat];
      const pulse = Math.sin(frame * 0.05);
      ctx.shadowBlur = running ? 0 : 10 + pulse * 5;
      ctx.shadowColor = chargeColor;
      ctx.fillStyle = chargeColor;
      ctx.beginPath();
      ctx.roundRect(cx - 10 - pulse, cy - 10 - pulse, 20 + pulse * 2, 20 + pulse * 2, 4);
      ctx.fill();
      ctx.shadowBlur = 0;

      ctx.font = `900 8px ${TECH_FONT}`;
      ctx.fillStyle = T.bg;
      ctx.textAlign = "center";
      ctx.fillText("HE", cx, cy + 3);

      if (!running) {
        ctx.fillStyle = T.orange;
        for (let i = 0; i < 15; i++) {
          const a = prng(frame, i) * Math.PI * 2;
          const r = 20 + ((frame * 0.2 + prng(frame, i + 1) * 30) % 50);
          ctx.globalAlpha = Math.max(0, 1 - (r - 20) / 50);
          ctx.beginPath();
          ctx.arc(cx + Math.cos(a) * r, cy + Math.sin(a) * r, 1.5, 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.globalAlpha = 1;
      }

      if (running) {
        const r = progress * (W - 40);
        const alpha = Math.max(0, 1 - progress);

        ctx.strokeStyle = `rgba(255, 255, 255, ${alpha * 0.7})`;
        ctx.lineWidth = 2 + (1 - progress) * 6;
        ctx.beginPath();
        ctx.arc(cx, cy, r, -Math.PI / 2.2, Math.PI / 2.2);
        ctx.stroke();

        if (progress < 0.4) {
          const fireR = r * 0.6;
          const fireGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, fireR);
          fireGrad.addColorStop(0, T.white);
          fireGrad.addColorStop(0.3, T.orange);
          fireGrad.addColorStop(1, "transparent");
          ctx.fillStyle = fireGrad;
          ctx.beginPath();
          ctx.arc(cx, cy, fireR, 0, Math.PI * 2);
          ctx.fill();
        }

        ctx.strokeStyle = `rgba(76, 201, 240, ${alpha * 0.2})`;
        ctx.lineWidth = 15;
        ctx.beginPath();
        if (r > 10) {
          ctx.arc(cx, cy, r - 10, -Math.PI / 2.2, Math.PI / 2.2);
          ctx.stroke();
        }
      }

      const tgt = Math.min(cx + distance * 3, W - 30);

      const barrierX = cx + distance * 1.5;
      if (barrier !== "none") {
        const barrierColor = { sandbag: "#8B7355", concrete: "#808080", aqueous_foam: T.cyan, composite: T.green }[barrier];
        ctx.fillStyle = barrierColor;
        ctx.globalAlpha = 0.7;
        ctx.fillRect(barrierX - 5, cy - 30, 10, 60);
        ctx.globalAlpha = 1;
        ctx.font = `600 7px ${TECH_FONT}`;
        ctx.fillStyle = T.dimText;
        ctx.textAlign = "center";
        ctx.fillText(barrier.toUpperCase().replace("_", " "), barrierX, cy + 40);
      }

      ctx.strokeStyle = T.green;
      ctx.setLineDash([5, 5]);
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(tgt, 20);
      ctx.lineTo(tgt, H - 20);
      ctx.stroke();
      ctx.setLineDash([]);

      ctx.font = `800 10px ${MONO_FONT}`;
      ctx.fillStyle = T.green;
      ctx.globalAlpha = 0.5 + Math.sin(frame * 0.08) * 0.5;
      ctx.fillText(`${distance}m STANDOFF`, tgt - 10, 15);
      ctx.globalAlpha = 1;

      if (running && progress * (W - 40) >= tgt - cx) {
        ctx.fillStyle = T.red;
        ctx.beginPath();
        ctx.arc(tgt, cy, 10, 0, Math.PI * 2);
        ctx.fill();
        ctx.font = `900 10px ${TECH_FONT}`;
        ctx.fillText("IMPACT", tgt - 20, cy - 15);
      }
    },
    [running, time, charge, distance, heMat, progress, barrier],
    { animate: true }
  );

  const profileRef = useCanvas(
    (ctx, W, H) => {
      const theme = getCanvasTheme();
      ctx.fillStyle = theme.canvasBackground;
      ctx.fillRect(0, 0, W, H);

      const padL = 30,
        padR = 10,
        padT = 8,
        padB = 15;
      const plotW = W - padL - padR,
        plotH = H - padT - padB;

      const thresholds = [
        { val: 0.07, label: "Glass", color: T.gold },
        { val: 0.35, label: "Ear", color: T.orange },
        { val: 2.0, label: "Lung", color: T.red },
      ];
      thresholds.forEach(({ val, label, color }) => {
        const y = padT + plotH * (1 - Math.min(1, Math.log10(val + 1) / Math.log10(6)));
        ctx.strokeStyle = `${color}40`;
        ctx.setLineDash([3, 3]);
        ctx.beginPath();
        ctx.moveTo(padL, y);
        ctx.lineTo(padL + plotW, y);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.font = `600 6px ${TECH_FONT}`;
        ctx.fillStyle = color;
        ctx.textAlign = "right";
        ctx.fillText(`${label} ${val}`, padL - 2, y + 3);
      });

      ctx.strokeStyle = T.red;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      for (let i = 0; i <= 50; i++) {
        const d = 2 + (i / 50) * 98;
        const z = d / Math.pow(Number(tntEq), 1 / 3);
        const logZ = Math.log10(z);
        const logP = 2.78 - 1.6 * logZ - 0.198 * logZ * logZ;
        const op = Math.pow(10, logP);
        const x = padL + (d / 100) * plotW;
        const y = padT + plotH * (1 - Math.min(1, Math.log10(op + 1) / Math.log10(6)));
        i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
      }
      ctx.stroke();

      const curX = padL + (distance / 100) * plotW;
      ctx.strokeStyle = T.green;
      ctx.setLineDash([3, 3]);
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(curX, padT);
      ctx.lineTo(curX, padT + plotH);
      ctx.stroke();
      ctx.setLineDash([]);

      ctx.font = `600 7px ${TECH_FONT}`;
      ctx.fillStyle = T.dimText;
      ctx.textAlign = "center";
      ctx.fillText("Distance (m)", W / 2, H - 2);
    },
    [charge, distance, heMat, tntEq],
  );

  useEffect(() => {
    if (!running) return;
    const start = performance.now();
    const tick = (now) => {
      const dt = (now - start) / 1000;
      setTime(dt);
      if (dt < 2) animRef.current = requestAnimationFrame(tick);
      else {
        setRunning(false);
        setTime(2);
      }
    };
    animRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(animRef.current);
  }, [running]);

  const reset = () => {
    cancelAnimationFrame(animRef.current);
    setRunning(false);
    setTime(0);
  };

  const buildPrompt = useCallback(
    () =>
      `Detonation blast effects simulation — current parameters:
ROLE: "You are an expert in detonics and blast effects. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Explosive material: ${heMat.toUpperCase()}
2. Charge mass: ${charge} kg
3. TNT equivalent: ${tntEq} kg
4. Stand-off distance: ${distance} m
5. Velocity of detonation: ${(vod / 1000).toFixed(2)} km/s
6. Hopkinson-Cranz scaled distance Z: ${scaledDist.toFixed(1)} m/kg^(1/3)
7. Peak overpressure at standoff: ${peakOPDisplay} bar
8. Impulse: ${impulse} kPa·ms
9. Arrival time: ${arrivalMs} ms
10. Barrier type: ${barrier}
11. Mitigated overpressure: ${mitigatedOP} bar
12. Application context: ${application}

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 — SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
