import { useState, useRef, useEffect, useCallback, useMemo } from "react";
import { T, TECH_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, DataBox, DataRow, InfoBox, SimCanvas, ActionBtn, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";


export default function ExplosiveDetectionSim() {
  const [method, setMethod] = useState("raman");
  const [explosive, setExplosive] = useState("rdx");
  const [scanning, setScanning] = useState(false);
  const [result, setResult] = useState(null);
  const [scanProg, setScanProg] = useState(0);
  const animRef = useRef(null);

  const methods = {
    fluorescence: { time: 2, sensitivity: "ppm", fp: 5, label: "Fluorescence" },
    raman: { time: 4, sensitivity: "ppb", fp: 1, label: "Raman" },
    canine: { time: 1, sensitivity: "ppt", fp: 8, label: "Canine 🐕" },
    ion_mobility: { time: 3, sensitivity: "ppb", fp: 2, label: "IMS" },
  };

  const explosives = {
    tnt: { color: T.gold, name: "TNT", det: true },
    rdx: { color: T.red, name: "RDX", det: true },
    petn: { color: T.orange, name: "PETN", det: true },
    hmx: { color: T.purple, name: "HMX", det: true },
    tatp: { color: T.cyan, name: "TATP", det: true },
  };

  const m = methods[method];
  const s = explosives[explosive];

  // 1. ADD real detection physics based on method
  const { snr, lod, prob, falseAlarm } = useMemo(() => {
    const laserPower = 100; // mW
    const exposureTime = 20; // ms
    const distance = 0.5; // m
    const temperature = 25; // °C

    // Different explosives have different vapor pressures -> different detectability
    const vaporPressure = { tnt: 5.8e-6, rdx: 4.1e-9, petn: 3.8e-8, hmx: 3.3e-11, tatp: 6.1e-2 }; // Torr at 25°C
    const concentration = vaporPressure[explosive]; 

    let _snr = 0, _lod = 10, _prob = 0;

    if (method === "raman") {
      // Raman spectroscopy: signal-to-noise depends on laser power and exposure time
      // Real SNR formula: SNR ∝ sqrt(power * time) / distance²
      _snr = Math.round(Math.sqrt(laserPower * exposureTime) / (distance * distance + 1));
      _lod = 10; // ppb
      _prob = _snr > 15 ? 99 : 85; 
    } 
    else if (method === "ion_mobility") {
      // Ion Mobility Spectrometry (IMS): drift time depends on molecular mass
      const imsResolution = 1 / (0.5 + temperature * 0.002); // resolution degrades with temp
      _snr = Math.round(imsResolution * 20);
      _lod = 0.1; // 100 ppt -> 0.1 ppb
      _prob = 96;
    } 
    else if (method === "fluorescence") {
      // Fluorescence quenching: explosive molecules quench polymer fluorescence
      // Stern-Volmer: F0/F = 1 + Ksv * [Q]
      const quenchFactor = 1 + 25 * (concentration * 1e6); // Ksv ≈ 25
      _snr = Math.round(quenchFactor * 10);
      _lod = 1000; // 1 ppm -> 1000 ppb
      _prob = quenchFactor > 1.05 ? 92 : 45;
    } 
    else if (method === "canine") {
      // Canine detection: probability based on concentration and wind
      _prob = Math.min(99, Math.round(40 + 50 * Math.log10(concentration * 1e9 + 1)));
      _snr = _prob > 50 ? 30 : 5; // Virtual SNR for dogs
      _lod = 0.001; // 1 ppt -> 0.001 ppb
    }

    return {
      snr: _snr,
      lod: _lod,
      prob: Math.max(0, _prob),
      falseAlarm: m.fp
    };
  }, [method, explosive, m.fp]);

  const startScan = () => {
    if (scanning) return;
    setScanning(true);
    setResult(null);
    setScanProg(0);
    const start = performance.now();
    const tick = (now) => {
      const p = Math.min((now - start) / (m.time * 1000), 1);
      setScanProg(p);
      if (p < 1) animRef.current = requestAnimationFrame(tick);
      else {
        setScanning(false);
        // Probability check
        const detected = Math.random() * 100 <= prob;
        setResult(detected ? "DETECTED" : "CLEAR");
      }
    };
    animRef.current = requestAnimationFrame(tick);
  };

  useEffect(() => () => cancelAnimationFrame(animRef.current), []);

  const buildPrompt = useCallback(
    () =>
      `Explosive detection simulation — current parameters:
ROLE: "You are an expert in explosive detection. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Detection method: ${m.label}
2. Explosive target: ${s.name}
3. Detection achieved: ${result ?? "not yet scanned"}
4. SNR: ${snr} dB
5. Limit of Detection (LOD): ${lod} ppb
6. Confidence: ${prob}%
7. False positive rate: ${falseAlarm}%

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these physical parameters (SNR, LOD). Are they realistic for ${m.label}? Why is ${s.name}'s vapor pressure significant here?
Part 2 — SAFETY & RISK: What are the failure modes (false alarm rate: ${falseAlarm}%)? What would a bomb technician watch for?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs and ECIL's Raman detectors? Reference paper FA-series at HEMCE.`,
    [m, s, result, snr, lod, prob, falseAlarm],
  );

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const theme = getCanvasTheme();

      // Technical background
      const bg = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, W / 2);
      bg.addColorStop(0, theme.canvasBackground);
      bg.addColorStop(1, theme.canvasSurface);
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      const cx = W / 2,
        cy = H / 2;

      // Sample Container (Suitcase/Package)
      ctx.fillStyle = "#1A202C";
      ctx.strokeStyle = `${T.accent}30`;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.roundRect(W / 2 - 60, cy - 40, 120, 80, 8);
      ctx.fill();
      ctx.stroke();

      // Sample Interior (The chemical signature area)
      ctx.fillStyle = `${s.color}15`;
      ctx.fillRect(W / 2 - 50, cy - 30, 100, 60);

      // Scanner Beam
      if (scanning) {
        const beamY = cy - 40 + scanProg * 80;
        const beamGrad = ctx.createLinearGradient(W / 2 - 60, beamY, W / 2 + 60, beamY);
        beamGrad.addColorStop(0, "transparent");
        beamGrad.addColorStop(0.5, method === "raman" ? T.purple : T.cyan);
        beamGrad.addColorStop(1, "transparent");

        ctx.strokeStyle = beamGrad;
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(W / 2 - 65, beamY);
        ctx.lineTo(W / 2 + 65, beamY);
        ctx.stroke();

        // Beam Glow
        ctx.globalAlpha = 0.2;
        ctx.fillStyle = method === "raman" ? T.purple : T.cyan;
        ctx.fillRect(W / 2 - 60, beamY - 5, 120, 10);
        ctx.globalAlpha = 1;

        // Sampling Particles (for IMS/Canine)
        if (method === "ion_mobility" || method === "canine") {
          for (let i = 0; i < 5; i++) {
            const px = W / 2 - 60 + prng(frame, i * 2) * 120;
            const py = beamY + (prng(frame, i * 2 + 1) - 0.5) * 10;
            ctx.fillStyle = s.color;
            ctx.beginPath();
            ctx.arc(px, py, 1, 0, Math.PI * 2);
            ctx.fill();
          }
        }
      }

      // Spectrum Analyzer (Bottom)
      const gx = 20,
        gy = H - 35,
        gw = W - 40,
        gh = 25;
      ctx.strokeStyle = `${T.accent}20`;
      ctx.strokeRect(gx, gy, gw, gh);

      if (scanning || result) {
        ctx.strokeStyle = scanning ? T.accent : result === "DETECTED" ? T.red : T.green;
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.moveTo(gx, gy + gh);
        for (let x = 0; x < gw; x += 2) {
          let iy = Math.sin(x * 0.2 + performance.now() / 100) * 2;
          // Peak for detected explosive
          if (s.det && Math.abs(x - gw / 2) < 20) {
            iy -= (scanning ? scanProg : 1) * 15 * Math.sin(((x - (gw / 2 - 20)) / 40) * Math.PI);
          }
          ctx.lineTo(gx + x, gy + gh * 0.8 + iy);
        }
        ctx.stroke();
      }

      // Detection HUD Overlay
      if (result === "DETECTED") {
        ctx.strokeStyle = T.red;
        ctx.lineWidth = 2;
        ctx.strokeRect(W / 2 - 65, cy - 45, 130, 90);

        // Target Reticle corners
        const rSize = 10;
        ctx.beginPath();
        ctx.moveTo(W / 2 - 65, cy - 35);
        ctx.lineTo(W / 2 - 65, cy - 45);
        ctx.lineTo(W / 2 - 55, cy - 45);
        ctx.moveTo(W / 2 + 65, cy - 35);
        ctx.lineTo(W / 2 + 65, cy - 45);
        ctx.lineTo(W / 2 + 55, cy - 45);
        ctx.moveTo(W / 2 - 65, cy + 35);
        ctx.lineTo(W / 2 - 65, cy + 45);
        ctx.lineTo(W / 2 - 55, cy + 45);
        ctx.moveTo(W / 2 + 65, cy + 35);
        ctx.lineTo(W / 2 + 65, cy + 45);
        ctx.lineTo(W / 2 + 55, cy + 45);
        ctx.stroke();

        ctx.font = `900 10px ${TECH_FONT}`;
        ctx.fillStyle = T.red;
        ctx.textAlign = "center";
        ctx.fillText("! THREAT IDENTIFIED: " + s.name.toUpperCase(), W / 2, cy - 50);
        ctx.textAlign = "left";
      } else if (result === "CLEAR") {
        ctx.font = `900 10px ${TECH_FONT}`;
        ctx.fillStyle = T.green;
        ctx.textAlign = "center";
        ctx.fillText("✓ SAMPLE VERIFIED: CLEAR", W / 2, cy - 50);
        ctx.textAlign = "left";
      }

      // Status / Mode Labels
      ctx.font = `800 8px ${TECH_FONT}`;
      ctx.fillStyle = T.dimText;
      ctx.fillText(`METHOD: ${m.label.toUpperCase()}`, 20, 15);
      ctx.fillText(`SENSITIVITY SNR: ${snr}`, W - 100, 15);
    },
    [scanning, scanProg, result, method, explosive, s, m, snr],
    { animate: true },
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={380} height={180} maxWidth={380} />
      <PillRow>
        <Pill
          active={method === "fluorescence"}
          onClick={() => { setResult(null); setMethod("fluorescence"); }}
          color={T.orange}
        >
          Fluorescence
        </Pill>
        <Pill
          active={method === "raman"}
          onClick={() => { setResult(null); setMethod("raman"); }}
          color={T.purple}
        >
          Raman
        </Pill>
        <Pill
          active={method === "ion_mobility"}
          onClick={() => { setResult(null); setMethod("ion_mobility"); }}
          color={T.accent}
        >
          IMS
        </Pill>
        <Pill
          active={method === "canine"}
          onClick={() => { setResult(null); setMethod("canine"); }}
          color={T.gold}
        >
          Canine 🐕
        </Pill>
      </PillRow>

      <PillRow>
        {Object.entries(explosives).map(([k, v]) => (
          <Pill
            key={k}
            active={explosive === k}
            onClick={() => {
              setResult(null);
              setExplosive(k);
            }}
            color={v.color}
          >
            {v.name}
          </Pill>
        ))}
      </PillRow>

      <DataRow>
        <DataBox label="SNR" value={snr} unit="dB" color={snr > 20 ? T.green : T.orange} />
        <DataBox label="LOD" value={lod < 1 ? lod : Math.round(lod)} unit="ppb" color={T.cyan} />
        <DataBox label="Confidence" value={prob} unit="%" color={prob > 80 ? T.green : T.orange} />
        <DataBox label="False Alarm" value={falseAlarm} unit="%" color={falseAlarm > 5 ? T.red : T.green} />
      </DataRow>

      <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
        <ActionBtn onClick={startScan} disabled={scanning} color={T.accent}>
          {scanning ? `SCANNING... ${(scanProg * 100).toFixed(0)}%` : "🔬 SCAN SAMPLE"}
        </ActionBtn>
      </div>

      <InfoBox>
        DRDO's HEMRL and CFEES develop field-portable explosive detection kits. ECIL Hyderabad builds Raman-based detectors for airport screening. Paper FA-series at HEMCE covers advanced detection techniques. Different explosives have varying vapor pressures (TATP is high, HMX is low), radically altering detection probability for methods like IMS or Canine tracking.
      </InfoBox>

      <AIInsight buildPrompt={buildPrompt} color={T.pink} />
      <ExportBtn
        simId="explosive_detection"
        getData={() => ({ method, explosive, snr, lod, prob, falseAlarm, result })}
        color={T.pink}
      />
    </div>
  );
}

import { useState, useMemo } from "react";
import { useCanvas, T, prng, getCanvasTheme } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";

export function GreenPropellantSim() {
  const [propellant, setPropellant] = useState("adn_water");
  const [chamberP, setChamberP] = useState(1.5);
  const [preheaterTemp, setPreheaterTemp] = useState(300);

  const propData = {
    adn_water:    { isp: 220, density: 1.24, tFlame: 1900, toxicity: 0, preheatMin: 150, catalyst: "LiAlO₂", color: "#6ee7b7", label: "ADN/Water" },
    han_methanol: { isp: 266, density: 1.42, tFlame: 2100, toxicity: 0, preheatMin: 300, catalyst: "Ir/Al₂O₃", color: "#38bdf8", label: "HAN/Methanol" },
    lmp103s:      { isp: 252, density: 1.24, tFlame: 1700, toxicity: 0, preheatMin: 250, catalyst: "LiAlO₂", color: "#a78bfa", label: "LMP-103S" },
    af_m315e:     { isp: 266, density: 1.47, tFlame: 2160, toxicity: 0, preheatMin: 350, catalyst: "Ir/Al₂O₃", color: "#f472b6", label: "AF-M315E" },
  };
  const pd = propData[propellant];

  const hydrazine = { isp: 230, density: 1.01, toxicity: 100 };

  const actualIsp = Math.round(pd.isp * (0.8 + 0.2 * chamberP / 3.0));
  const rhoIspRatio = ((actualIsp * pd.density) / (hydrazine.isp * hydrazine.density) * 100).toFixed(0);

  const catalystOK = preheaterTemp >= pd.preheatMin;
  const startupDelay = catalystOK ? Math.round(500 / (preheaterTemp - pd.preheatMin + 1)) : "∞";
  const thrust = catalystOK ? (chamberP * 0.8 * pd.density).toFixed(2) : 0;

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const theme = getCanvasTheme();
      ctx.fillStyle = theme.canvasBackground;
      ctx.fillRect(0, 0, W, H);

      const cy = (H - 40) / 2; // Leave space for bottom bar

      // Thruster drawing
      // Tank (left)
      const tankX = 20, tankW = 60, tankH = 80;
      ctx.fillStyle = "#334155";
      ctx.beginPath();
      ctx.roundRect(tankX, cy - tankH/2, tankW, tankH, 8);
      ctx.fill();

      // Tank color
      ctx.fillStyle = pd.color;
      ctx.beginPath();
      ctx.roundRect(tankX + 5, cy - tankH/2 + 5, tankW - 10, tankH - 10, 4);
      ctx.fill();

      // Feed pipe
      ctx.fillStyle = "#475569";
      ctx.fillRect(tankX + tankW, cy - 10, 30, 20);

      // Catalyst Bed
      const catX = tankX + tankW + 30, catW = 70, catH = 50;
      ctx.fillStyle = "#1e293b";
      ctx.beginPath();
      ctx.roundRect(catX, cy - catH/2, catW, catH, 4);
      ctx.fill();

      // Preheater coil
      const coilColor = preheaterTemp > 400 ? T.red : preheaterTemp > 200 ? T.orange : "#64748b";
      ctx.strokeStyle = coilColor;
      ctx.lineWidth = 3;
      for (let i = 0; i < 5; i++) {
         ctx.beginPath();
         ctx.moveTo(catX + 10 + i * 12, cy - catH/2 - 2);
         ctx.lineTo(catX + 10 + i * 12 + 6, cy + catH/2 + 2);
         ctx.stroke();
      }

      // Decomposition Chamber
      const chmX = catX + catW, chmW = 60, chmH = 40;
      ctx.fillStyle = "#0f172a";
      ctx.fillRect(chmX, cy - chmH/2, chmW, chmH);

      // Nozzle
      const nozX = chmX + chmW, nozW = 50;
      ctx.fillStyle = "#334155";
      ctx.beginPath();
      ctx.moveTo(nozX, cy - chmH/2);
      ctx.lineTo(nozX + nozW, cy - chmH - 10);
      ctx.lineTo(nozX + nozW, cy + chmH + 10);
      ctx.lineTo(nozX, cy + chmH/2);
      ctx.fill();

      if (!catalystOK) {
        // Red X over catalyst bed
        ctx.strokeStyle = T.red;
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.moveTo(catX + 10, cy - 15); ctx.lineTo(catX + catW - 10, cy + 15);
        ctx.moveTo(catX + 10, cy + 15); ctx.lineTo(catX + catW - 10, cy - 15);
        ctx.stroke();

        ctx.fillStyle = T.red;
        ctx.font = `800 12px monospace`;
        ctx.textAlign = "center";
        ctx.fillText("PREHEAT REQUIRED", catX + catW/2, cy - catH/2 - 15);
      } else {
        // Glowing chamber based on TFlame
        const glow = ctx.createLinearGradient(chmX, 0, chmX + chmW, 0);
        glow.addColorStop(0, "rgba(255,255,255,0.8)");
        glow.addColorStop(1, "rgba(56, 189, 248, 0.4)"); 
        ctx.fillStyle = glow;
        ctx.fillRect(chmX, cy - chmH/2, chmW, chmH);

        // Animated gas flow through catalyst->chamber->nozzle
        ctx.fillStyle = "rgba(167, 243, 208, 0.6)"; // subtle green tint
        for (let i = 0; i < 20; i++) {
           const px = catX + ((frame * 2 + prng(frame, i)*50) % (catW + chmW));
           const py = cy + (prng(frame, i + 1) - 0.5) * (catH - 10);
           ctx.beginPath();
           ctx.arc(px, py, 2 + prng(frame, i+2)*2, 0, Math.PI*2);
           ctx.fill();
        }

        // Exhaust plume
        const exGrad = ctx.createLinearGradient(nozX + nozW, 0, W, 0);
        exGrad.addColorStop(0, "rgba(167, 243, 208, 0.8)");
        exGrad.addColorStop(1, "transparent");
        ctx.fillStyle = exGrad;
        ctx.beginPath();
        ctx.moveTo(nozX + nozW, cy - chmH - 5);

        // Wavering plume end
        for (let i=0; i<10; i++) {
           const wy = cy - chmH*1.5 + (i/9) * chmH * 3;
           const wx = W - 20 + Math.sin(frame*0.1 + i) * 10;
           ctx.lineTo(wx, wy); 
        }

        ctx.lineTo(nozX + nozW, cy + chmH + 5);
        ctx.fill();
      }

      ctx.textAlign = "left";

      // Comparison bar at bottom
      const barY = H - 30;
      const originX = 120;
      const maxBarW = W - originX - 40;
      const refIsp = hydrazine.isp * hydrazine.density;
      const curIsp = actualIsp * pd.density;

      const widthRef = maxBarW * 0.6; // Scale so 60% is hydrazine
      const widthCur = widthRef * (curIsp / refIsp);

      ctx.fillStyle = T.dimText;
      ctx.font = `800 10px monospace`;
      ctx.fillText("Density-Isp:", 10, barY + 12);

      // Hydrazine Bar
      ctx.fillStyle = T.orange;
      ctx.fillRect(originX, barY - 2, widthRef, 10);
      ctx.fillStyle = T.black;
      ctx.font = `800 9px monospace`;
      ctx.fillText("N2H4", originX + 5, barY + 6);

      // Green Prop Bar
      ctx.fillStyle = rhoIspRatio > 100 ? T.green : T.purple;
      ctx.fillRect(originX, barY + 12, widthCur, 10);
      ctx.fillStyle = T.black;
      ctx.fillText(pd.label, originX + 5, barY + 20);

      // 100% Marker Line
      ctx.strokeStyle = "rgba(255,255,255,0.3)";
      ctx.beginPath();
      ctx.moveTo(originX + widthRef, barY - 10);
      ctx.lineTo(originX + widthRef, barY + 30);
      ctx.stroke();

    },
    [propellant, chamberP, preheaterTemp, pd, actualIsp, rhoIspRatio, catalystOK],
    { animate: true }
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={200} />

      <PillRow>
        <Pill active={propellant === "adn_water"} onClick={() => setPropellant("adn_water")} color="#6ee7b7">ADN/Water</Pill>
        <Pill active={propellant === "han_methanol"} onClick={() => setPropellant("han_methanol")} color="#38bdf8">HAN/Meth</Pill>
        <Pill active={propellant === "lmp103s"} onClick={() => setPropellant("lmp103s")} color="#a78bfa">LMP-103S</Pill>
        <Pill active={propellant === "af_m315e"} onClick={() => setPropellant("af_m315e")} color="#f472b6">AF-M315E</Pill>
      </PillRow>

      <Slider label="Chamber Pressure" value={chamberP} onChange={setChamberP} min={0.5} max={3.0} step={0.1} unit="MPa" color={T.cyan} />
      <Slider label="Preheater Temp" value={preheaterTemp} onChange={setPreheaterTemp} min={200} max={600} unit="°C" color={T.orange} />

      <DataRow>
        <DataBox label="Isp" value={actualIsp} unit="s" color={T.green} />
        <DataBox label="ρIsp" value={(actualIsp * pd.density).toFixed(0)} unit="kg·s/m³" color={T.purple} />
        <DataBox label="vs Hydrazine" value={rhoIspRatio} unit="%" color={rhoIspRatio > 100 ? T.green : T.orange} />
      </DataRow>
      <DataRow style={{marginTop: 8}}>
        <DataBox label="Thrust" value={thrust} unit="N" color={T.accent} />
        <DataBox label="Startup" value={startupDelay} unit="ms" color={catalystOK ? T.green : T.red} />
        <DataBox label="Toxicity" value="ZERO ✓" unit="" color={T.green} />
      </DataRow>

      <div style={{ fontSize: 10, color: T.dimText, textAlign: "center", marginTop: 8, marginBottom: 8, fontFamily: 'monospace' }}>
        Requires {pd.preheatMin}°C using {pd.catalyst} catalyst.
        {!catalystOK && <strong style={{color: T.red, marginLeft: 8}}>⚠ PREHEAT REQUIRED</strong>}
      </div>

      <InfoBox>
         Green propellants (ADN, HAN) replace toxic hydrazine (N₂H₄) for spacecraft thrusters. LMP-103S powered Sweden's PRISMA and SkySat satellites. AF-M315E offers 50% higher density-Isp. ISRO is evaluating ADN-based thrusters for future missions. Key challenge: catalyst preheating (300-500°C) for reliable ignition. Paper FA16-P06 at HEMCE 2026 covers catalytic decomposition of ADN.
      </InfoBox>

      <AIInsight
        buildPrompt={() => `Focus domain: green propellant chemistry and low-toxicity thruster systems.
Context: You are evaluating a green thruster using ${pd.label} at ${chamberP} MPa with a preheater set to ${preheaterTemp}°C.
Current thrust: ${thrust}N. Relative density-Isp compared to hydrazine: ${rhoIspRatio}%.
Mention paper FA16-P06 from HEMCE 2026 covering catalytic decomposition of ADN. Analyze the challenges of catalyst preheating for ${pd.catalyst} and how this compares to traditional hydrazine handling.
`}
        color={T.green}
      />
      <ExportBtn simId="greenprop" getData={() => ({ propellant, chamberP, preheaterTemp, thrust, isp: actualIsp })} color={T.green} />
    </div>
  );
}

