import { useState, useRef, useCallback, useMemo } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";

import { MISSILE_DB } from "../data/missileDB";

export default function HybridRocketSim() {
  const related = MISSILE_DB.filter((m) => m.relatedSimId === "hybrid");
  const [throttle, setThrottle] = useState(50);
  const [fuel, setFuel] = useState("paraffin");
  const [oxidizer, setOxidizer] = useState("n2o");
  const [running, setRunning] = useState(false);
  const ivRef = useRef(null);

  const fd = { paraffin: { rate: 3.2, isp: 250 }, htpb: { rate: 1.0, isp: 240 }, abs: { rate: 1.5, isp: 230 } }[fuel];
  const od = { n2o: { name: "N₂O", mult: 1.0 }, lox: { name: "LOX", mult: 1.3 }, h2o2: { name: "H₂O₂", mult: 1.1 } }[
    oxidizer
  ];

  const regRate = useMemo(() => (fd.rate * (throttle / 100) * od.mult).toFixed(1), [fd.rate, throttle, od.mult]);
  const optimalOF = {
    "paraffin-n2o": 7.5,
    "paraffin-lox": 2.8,
    "paraffin-h2o2": 6.0,
    "htpb-n2o": 8.0,
    "htpb-lox": 2.5,
    "htpb-h2o2": 6.5,
    "abs-n2o": 7.0,
    "abs-lox": 2.2,
    "abs-h2o2": 5.5,
  };
  const optOF = optimalOF[`${fuel}-${oxidizer}`];
  const fuelDensity = { paraffin: 900, htpb: 920, abs: 1040 }[fuel];
  const oxFlux = (throttle / 100) * od.mult * 200;
  const regRateMS = Number(regRate) * 0.001;
  const ofRatio = (oxFlux / (fuelDensity * regRateMS + 0.001)).toFixed(1);
  const ofDeviation = Math.abs(Number(ofRatio) - optOF);
  const ispPenalty = Math.min(0.3, ofDeviation * 0.05);
  const actualIsp = Math.round(fd.isp * (1 - ispPenalty));
  const thrust = Math.round(((actualIsp * throttle) / 100) * od.mult * 0.4);
  const ofColor = ofDeviation > optOF * 0.2 ? T.red : ofDeviation > optOF * 0.1 ? T.orange : T.green;

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const cy = H / 2;
      const theme = getCanvasTheme();

      // Background for test stand atmosphere
      const bg = ctx.createRadialGradient(W / 2, cy, 0, W / 2, cy, W);
      bg.addColorStop(0, theme.canvasBackground);
      bg.addColorStop(1, theme.canvasSurface);
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      // Oxidizer Tank (Cryogenic Look)
      ctx.fillStyle = "#1A3A5A";
      ctx.strokeStyle = T.accent;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.roundRect(10, cy - 30, 60, 60, 8);
      ctx.fill();
      ctx.stroke();

      // Tank frost effect
      ctx.strokeStyle = "rgba(255,255,255,0.05)";
      ctx.strokeRect(12, cy - 28, 56, 56);

      // Feed System / Valve
      ctx.strokeStyle = running ? T.cyan : `${T.cyan}30`;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(70, cy);
      ctx.lineTo(100, cy);
      ctx.stroke();

      // Injector Plate
      ctx.fillStyle = "#2D3748";
      ctx.fillRect(95, cy - 15, 8, 30);

      // Motor Casing (Combustor)
      ctx.fillStyle = "#1A202C";
      ctx.strokeStyle = `${T.accent}30`;
      ctx.beginPath();
      ctx.roundRect(103, cy - 35, 170, 70, 4);
      ctx.fill();
      ctx.stroke();

      // Solid Fuel Grain Regression Visualization
      const fc = fuel === "paraffin" ? "#F5DEB3" : fuel === "abs" ? "#8B8682" : "#A0522D";
      const regOffset = -2 + (throttle / 100) * 12 * Math.sin(frame * 0.03); // Visual flair for regression
      const portH = 15 + (throttle / 100) * 10;

      ctx.fillStyle = fc;
      // Top Grain
      ctx.beginPath();
      ctx.roundRect(107, cy - 30, 162, 30 - portH / 2, 2);
      ctx.fill();
      // Bottom Grain
      ctx.beginPath();
      ctx.roundRect(107, cy + portH / 2, 162, 30 - portH / 2, 2);
      ctx.fill();

      // Flow & Combustion Core
      if (running) {
        // Ox Flow Pulse
        const flowPulse = Math.sin(frame * 0.2) * 0.5 + 0.5;
        ctx.strokeStyle = `rgba(0, 180, 216, ${0.4 * flowPulse})`;
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.moveTo(70, cy);
        ctx.lineTo(100, cy);
        ctx.stroke();

        // Flame Core (Purplish hybrid flame)
        const fGrad = ctx.createLinearGradient(120, 0, 260, 0);
        fGrad.addColorStop(0, T.white);
        fGrad.addColorStop(0.3, T.purple);
        fGrad.addColorStop(1, "transparent");

        ctx.fillStyle = fGrad;
        ctx.globalAlpha = 0.5 + throttle / 200;
        ctx.beginPath();
        ctx.roundRect(110, cy - portH / 2 + 2, 150 + throttle * 0.5, portH - 4, 10);
        ctx.fill();
        ctx.globalAlpha = 1;

        // Combustion Particles
        for (let i = 0; i < 15; i++) {
          const px = 110 + prng(frame, i * 3) * 150;
          const py = cy + (prng(frame, i * 3 + 1) - 0.5) * portH;
          ctx.fillStyle = `rgba(138, 43, 226, ${prng(frame, i * 3 + 2)})`;
          ctx.beginPath();
          ctx.arc(px, py, 1.5, 0, Math.PI * 2);
          ctx.fill();
        }
      }

      // Nozzle Expansion
      ctx.fillStyle = "#2D3748";
      ctx.beginPath();
      ctx.moveTo(273, cy - 15);
      ctx.lineTo(300, cy - 35);
      ctx.lineTo(300, cy + 35);
      ctx.lineTo(273, cy + 15);
      ctx.closePath();
      ctx.fill();
      ctx.strokeStyle = `${T.accent}40`;
      ctx.stroke();

      // Exhaust Plume
      if (running) {
        const eGrad = ctx.createLinearGradient(300, 0, 360, 0);
        eGrad.addColorStop(0, `${T.purple}66`);
        eGrad.addColorStop(1, "transparent");
        ctx.fillStyle = eGrad;
        ctx.beginPath();
        ctx.moveTo(300, cy - 30);
        ctx.lineTo(360, cy - 50);
        ctx.lineTo(360, cy + 50);
        ctx.lineTo(300, cy + 30);
        ctx.fill();
      }

      // HUD Text
      ctx.font = `900 9px ${TECH_FONT}`;
      ctx.textAlign = "center";
      ctx.fillStyle = T.accent;
      ctx.fillText(od.name.toUpperCase(), 40, cy - 35);
      ctx.fillStyle = T.orange;
      ctx.fillText("COMBUSTOR: " + fuel.toUpperCase(), 188, cy - 40);

      ctx.font = `800 8px ${MONO_FONT}`;
      ctx.fillStyle = T.dimText;
      ctx.fillText(`THRUST VECTOR: ${running ? "STABLE" : "NULL"}`, 188, cy + 45);
      ctx.textAlign = "left";
    },
    [running, throttle, fuel, oxidizer],
    { animate: true },
  );

  // Animation is driven by useCanvas with { animate: true }

  const buildPrompt = useCallback(
    () =>
      `Hybrid rocket motor simulation — current parameters:
ROLE: "You are an expert in hybrid combustion. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Solid fuel: ${fuel}
2. Fuel regression rate base: ${fd.rate} mm/s
3. Base fuel Isp: ${fd.isp} s
4. Liquid oxidizer: ${od.name}
5. Throttle setting: ${throttle}%
6. Fuel regression rate at current throttle: ${regRate} mm/s
7. Oxidizer/fuel ratio: ${ofRatio}
8. Optimal O/F: ${optOF}
9. O/F deviation: ${ofDeviation.toFixed(1)}
10. Actual Isp: ${actualIsp} s
11. Net thrust: ${thrust} kN
12. Engine running: ${running ? "YES" : "NO"}

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 — SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?
Related Indian systems: ${related.map((m) => m.name).join(", ")}`,
    [fuel, fd, od, throttle, regRate, ofRatio, optOF, ofDeviation, actualIsp, thrust, running, related],
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={370} height={120} maxWidth={370} />
      <PillRow>
        <Pill active={fuel === "paraffin"} onClick={() => setFuel("paraffin")} color={T.gold}>
          Paraffin
        </Pill>
        <Pill active={fuel === "htpb"} onClick={() => setFuel("htpb")} color={T.orange}>
          HTPB
        </Pill>
        <Pill active={fuel === "abs"} onClick={() => setFuel("abs")} color={T.gray}>
          ABS (3D)
        </Pill>
      </PillRow>
      <PillRow>
        <Pill active={oxidizer === "n2o"} onClick={() => setOxidizer("n2o")} color={T.cyan}>
          N₂O
        </Pill>
        <Pill active={oxidizer === "lox"} onClick={() => setOxidizer("lox")} color={T.accent}>
          LOX
        </Pill>
        <Pill active={oxidizer === "h2o2"} onClick={() => setOxidizer("h2o2")} color={T.green}>
          H₂O₂
        </Pill>
        <Pill active={running} onClick={() => setRunning(!running)} color={running ? T.red : T.green}>
          {running ? "⏹ Stop" : "▶ Run"}
        </Pill>
      </PillRow>
      <Slider label="Throttle" value={throttle} onChange={setThrottle} min={0} max={100} unit="%" color={T.green} />
      <DataRow>
        <DataBox label="Thrust" value={thrust} unit="kN" color={T.orange} />
        <DataBox label="Isp" value={actualIsp} unit="s" color={T.accent} />
        <DataBox label="O/F" value={ofRatio} unit="" color={ofColor} />
        <DataBox label="Reg Rate" value={regRate} unit="mm/s" color={T.gold} />
      </DataRow>
      <div style={{ fontSize: 10, color: T.dimText, textAlign: "center", marginTop: 2 }}>
        Optimal O/F for {fuel}/{oxidizer}: {optOF} — Current: {ofRatio}
        {ofDeviation > optOF * 0.2 ? " ⚠ Far from optimal" : " ✓ Near optimal"}
      </div>
      <InfoBox>
        <strong style={{ color: T.green }}>Hybrid advantage:</strong> Throttleable, restartable, inherently safer.{" "}
        {fuel === "paraffin"
          ? "Paraffin: 3× regression rate."
          : fuel === "abs"
            ? "ABS: 3D-printable grains."
            : "HTPB: standard baseline."}{" "}
        ISRO/HEMRL co-developing hybrid motors.
        {related.length > 0 && (
          <div style={{ marginTop: 8, borderTop: `1px solid ${T.glassBorder}`, paddingTop: 8 }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: T.accent, marginBottom: 4 }}>
              INDIAN SYSTEMS USING THIS TECHNOLOGY:
            </div>
            {related.map((m) => (
              <div key={m.id} style={{ fontSize: 10, color: T.gray, marginBottom: 2 }}>
                {m.image_emoji} <strong style={{ color: T.white }}>{m.name}</strong>
                {" — "}{m.propulsion.stages} | {m.performance.range}
                {m.sources[0] && (
                  <a href={m.sources[0].url} target="_blank" rel="noopener noreferrer"
                     style={{ color: T.accent, marginLeft: 4, fontSize: 9 }}>
                    [source]
                  </a>
                )}
              </div>
            ))}
          </div>
        )}
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.lime} />
      <ExportBtn simId="hybrid" getData={() => ({ fuel, oxidizer, throttle, thrust, regRate })} color={T.lime} />
    </div>
  );
}

import { useState, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";


export default function PressureVesselSim() {
  const [pressure, setPressure] = useState(5);
  const [thickness, setThickness] = useState(8);
  const [radius, setRadius] = useState(200);
  const [mat, setMat] = useState("steel");

  const ys = { steel: 700, aluminium: 280, composite: 450 }[mat];
  const hoop = (pressure * radius) / thickness;
  const axial = hoop / 2;
  const fos = ys / hoop;
  const burst = ((ys * thickness) / radius).toFixed(1);
  const safe = fos >= 1.5;
  const warn = fos >= 1 && fos < 1.5;
  const wallColor = hoop > ys ? T.red : hoop > ys * 0.67 ? T.gold : T.green;

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const cx = W / 2,
        cy = H / 2,
        p = pressure;
      const canvasTheme = getCanvasTheme();

      // Deep technical background
      const bg = ctx.createRadialGradient(cx, cy, 0, cx, cy, W / 2);
      bg.addColorStop(0, canvasTheme.bgStart);
      bg.addColorStop(1, canvasTheme.bgEnd);
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      const dr = 65,
        ww = Math.max(4, thickness * 0.7);

      // Internal Stress Heatmap (Glow)
      const stressP = Math.min(1.5, hoop / ys);
      const heatGrad = ctx.createRadialGradient(cx, cy, dr - ww, cx, cy, dr + ww);
      heatGrad.addColorStop(0, "transparent");
      heatGrad.addColorStop(0.5, stressP > 1.0 ? T.red : stressP > 0.7 ? T.orange : T.green);
      heatGrad.addColorStop(1, "transparent");

      ctx.globalAlpha = 0.3 * stressP;
      ctx.fillStyle = heatGrad;
      ctx.beginPath();
      ctx.arc(cx, cy, dr + 10, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;

      // Composite Winding Pattern / Vessel Structure
      ctx.strokeStyle = wallColor;
      ctx.lineWidth = ww;
      ctx.beginPath();
      ctx.arc(cx, cy, dr, 0, Math.PI * 2);
      ctx.stroke();

      // Fiber Winding details
      ctx.strokeStyle = "rgba(255,255,255,0.1)";
      ctx.lineWidth = 0.5;
      for (let i = 0; i < 36; i++) {
        const a = (i / 36) * Math.PI * 2;
        ctx.beginPath();
        ctx.moveTo(cx + Math.cos(a) * (dr - ww / 2), cy + Math.sin(a) * (dr - ww / 2));
        ctx.lineTo(cx + Math.cos(a + 0.4) * (dr + ww / 2), cy + Math.sin(a + 0.4) * (dr + ww / 2));
        ctx.stroke();
      }

      // Internal Pressure Vectors (Pulse)
      const pulse = Math.sin(performance.now() / 200) * 0.2 + 0.8;
      const pn = Math.min(pressure / 20, 1);
      ctx.strokeStyle = T.accent;
      ctx.lineWidth = 1;
      for (let i = 0; i < 12; i++) {
        const a = (i / 12) * Math.PI * 2,
          len = 10 + pn * 15 * pulse;
        ctx.beginPath();
        ctx.moveTo(cx + Math.cos(a) * (dr - ww / 2 - 2), cy + Math.sin(a) * (dr - ww / 2 - 2));
        ctx.lineTo(cx + Math.cos(a) * (dr - ww / 2 - 2 - len), cy + Math.sin(a) * (dr - ww / 2 - 2 - len));
        ctx.stroke();
      }

      // Safety Valve Venting (Particle Effect)
      if (stressP > 1.0) {
        ctx.fillStyle = T.white;
        for (let i = 0; i < 5; i++) {
          const vx = cx + prng(frame, i * 2) * 10 - 5;
          const vy = cy - dr - ww - prng(frame, i * 2 + 1) * 30;
          ctx.globalAlpha = 0.4;
          ctx.beginPath();
          ctx.arc(vx, vy, 2, 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.globalAlpha = 1;
        ctx.font = `900 8px ${MONO_FONT}`;
        ctx.fillStyle = T.red;
        ctx.fillText("VALVE VENTING", cx + dr, cy - dr - 10);
      }

      // Labels & HUD
      ctx.font = `900 10px ${TECH_FONT}`;
      ctx.fillStyle = T.accent;
      ctx.textAlign = "center";
      ctx.fillText("UNIT: PRESSURE VESSEL", cx, cy + 4);

      // Indicators for Hoop Stress
      ctx.strokeStyle = T.orange;
      ctx.lineWidth = 2;
      const startA = -0.2,
        endA = 0.2;
      ctx.beginPath();
      ctx.arc(cx, cy, dr + ww + 10, startA, endA);
      ctx.stroke();
      ctx.beginPath();
      ctx.arc(cx, cy, dr + ww + 10, startA + Math.PI, endA + Math.PI);
      ctx.stroke();

      ctx.font = `bold 9px ${MONO_FONT}`;
      ctx.fillStyle = T.orange;
      ctx.fillText("STR: HOOP", cx + dr + 35, cy);

      ctx.fillStyle = wallColor;
      ctx.font = `900 11px ${TECH_FONT}`;
      ctx.fillText(safe ? "STATUS: STABLE" : warn ? "STATUS: MARGINAL" : "STATUS: CRITICAL", cx, H - 15);
      ctx.textAlign = "left";
    },
    [pressure, thickness, radius, mat, hoop, ys, fos],
    { animate: true },
  );

  const buildPrompt = useCallback(
    () =>
      `Pressure vessel structural integrity simulation — current parameters:
ROLE: "You are an expert in structural safety. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Material: ${mat}
2. Yield strength: ${ys} MPa
3. Internal pressure: ${pressure} MPa
4. Wall thickness: ${thickness} mm
5. Inner radius: ${radius} mm
6. Hoop stress (σ_h): ${hoop.toFixed(0)} MPa
7. Axial stress: ${axial.toFixed(0)} MPa
8. Factor of Safety: ${fos.toFixed(2)}
9. Burst pressure: ${burst} MPa
10. Status: ${!safe && !warn ? "YIELDED" : warn ? "CAUTION" : "SAFE"}

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 — SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?`,
    [mat, ys, pressure, thickness, radius, hoop, axial, fos, burst, safe, warn],
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={280} height={200} maxWidth={280} />
      <PillRow>
        <Pill active={mat === "steel"} onClick={() => setMat("steel")}>
          Steel 700MPa
        </Pill>
        <Pill active={mat === "aluminium"} onClick={() => setMat("aluminium")} color={T.gold}>
          Al 280MPa
        </Pill>
        <Pill active={mat === "composite"} onClick={() => setMat("composite")} color={T.green}>
          CFRP 450MPa
        </Pill>
      </PillRow>
      <Slider
        label="Internal Pressure"
        value={pressure}
        onChange={setPressure}
        min={1}
        max={25}
        step={0.5}
        unit=" MPa"
        color={T.accent}
      />
      <Slider
        label="Wall Thickness"
        value={thickness}
        onChange={setThickness}
        min={2}
        max={30}
        step={0.5}
        unit=" mm"
        color={T.orange}
      />
      <Slider
        label="Inner Radius"
        value={radius}
        onChange={setRadius}
        min={50}
        max={500}
        step={10}
        unit=" mm"
        color={T.gold}
      />
      <DataRow>
        <DataBox label="Hoop σ" value={hoop.toFixed(0)} unit="MPa" color={hoop > ys ? T.red : T.orange} />
        <DataBox label="Axial σ" value={axial.toFixed(0)} unit="MPa" color={T.accent} />
        <DataBox label="FoS" value={fos.toFixed(1)} unit="×" color={safe ? T.green : warn ? T.gold : T.red} />
        <DataBox label="Burst" value={burst} unit="MPa" color={T.red} />
      </DataRow>
      <InfoBox>
        <strong style={{ color: T.accent }}>σ_hoop = P×r/t.</strong> Orange arrows = circumferential stress. ASME
        requires FoS ≥ 1.5. Wall color: <span style={{ color: T.green }}>safe</span> /{" "}
        <span style={{ color: T.gold }}>caution</span> / <span style={{ color: T.red }}>yield exceeded</span>.
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.accent} />
      <ExportBtn
        simId="pressure_vessel"
        getData={() => ({
          mat,
          pressure,
          thickness,
          radius,
          hoop: hoop.toFixed(0),
          axial: axial.toFixed(0),
          fos: fos.toFixed(2),
        })}
        color={T.accent}
      />
    </div>
  );
}

import { useState, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";


export default function PropellantChemistrySim() {
  const [oxidizer, setOxidizer] = useState("ap");
  const [binder, setBinder] = useState("htpb");
  const [alPercent, setAlPercent] = useState(18);
  const [nano, setNano] = useState(false);

  const oxData = {
    ap: { isp: 260, green: false },
    an: { isp: 220, green: true },
    adn: { isp: 275, green: true },
    hmx: { isp: 285, green: false },
  };
  const bindData = { htpb: { isp: 0 }, gap: { isp: 15 }, pban: { isp: -5 } };
  const oxcol = { ap: "#4A90D9", an: T.green, adn: T.purple, hmx: T.red };
  const ox = oxData[oxidizer],
    bn = bindData[binder];
  const totalIsp = (ox.isp + bn.isp + alPercent * 1.2 + (nano ? 12 : 0)).toFixed(0);
  const density = (ox.isp > 260 ? 1.91 : 1.8) * 0.7 + (2.7 * alPercent) / 100 + 0.92 * 0.3;
  const sensitivity = oxidizer === "hmx" ? "HIGH" : oxidizer === "ap" ? "MED" : "LOW";
  const greenScore = (ox.green ? 70 : 20) + (binder === "gap" ? 15 : 0);

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const theme = getCanvasTheme();

      // Background for chemistry scene
      const bg = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, W / 2);
      bg.addColorStop(0, theme.canvasBackground);
      bg.addColorStop(1, theme.canvasSurface);
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, W, H);

      const cx = 80,
        cy = H / 2,
        r = 50;

      // Molecular Matrix Container
      ctx.strokeStyle = `${T.accent}30`;
      ctx.lineWidth = 1;
      ctx.strokeRect(20, 20, 120, H - 40);

      // Matrix Grains (Simulated Solid Matrix)
      const grainCount = 100;
      for (let i = 0; i < grainCount; i++) {
        const gx = 25 + (i % 10) * 11;
        const gy = 25 + Math.floor(i / 10) * 10;

        const seed = Math.sin(i * 0.5 + performance.now() / 500);
        let col = "#A0522D"; // Binder default

        const p = i / grainCount;
        if (p < ox.isp / 300) col = oxcol[oxidizer];
        else if (p < ox.isp / 300 + alPercent / 50) col = "#C0C0C0";

        ctx.fillStyle = col;
        ctx.globalAlpha = 0.6 + seed * 0.2;
        ctx.fillRect(gx, gy, 9, 8);
      }
      ctx.globalAlpha = 1;

      // Energy Density Spectrum (Right Side)
      const sx = 160,
        sy = 30,
        sw = W - 180,
        sh = H - 60;
      ctx.strokeStyle = `${T.accent}20`;
      ctx.strokeRect(sx, sy, sw, sh);

      // Grid Lines
      ctx.beginPath();
      for (let y = sy; y < sy + sh; y += 20) {
        ctx.moveTo(sx, y);
        ctx.lineTo(sx + sw, y);
      }
      ctx.stroke();

      // Stability Plot
      ctx.strokeStyle = T.accent;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(sx, sy + sh * 0.8);
      for (let x = 0; x < sw; x += 5) {
        const iy = Math.sin(x * 0.1 + performance.now() / 200) * 5 * (sensitivity === "HIGH" ? 3 : 1);
        ctx.lineTo(sx + x, sy + sh * 0.8 - (totalIsp / 350) * sh * 0.5 + iy);
      }
      ctx.stroke();

      // Nano-Enhancement Twinkle
      if (nano) {
        for (let i = 0; i < 15; i++) {
          const nx = 20 + prng(frame, i * 2) * 120;
          const ny = 20 + prng(frame, i * 2 + 1) * (H - 40);
          const s = Math.sin(performance.now() / 150 + i) * 0.5 + 0.5;
          ctx.fillStyle = T.gold;
          ctx.globalAlpha = s;
          ctx.beginPath();
          ctx.arc(nx, ny, 1, 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.globalAlpha = 1;
      }

      // HUD Text
      ctx.font = `900 9px ${TECH_FONT}`;
      ctx.fillStyle = T.accent;
      ctx.fillText("MATRIX: PROP-LOAD", 20, 15);
      ctx.fillText("ENERGY SPECTRUM (Isp)", sx, 25);

      ctx.font = `800 8px ${MONO_FONT}`;
      ctx.fillStyle = T.dimText;
      ctx.fillText(`MODE: ${nano ? "NANO-ENHANCED" : "STANDARD"}`, 160, H - 15);
    },
    [oxidizer, binder, alPercent, nano, totalIsp, sensitivity],
    { animate: true },
  );

  const buildPrompt = useCallback(
    () =>
      `Solid propellant chemistry formulation simulation — current parameters:
ROLE: "You are an expert in energetic materials chemistry. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Oxidizer: ${oxidizer.toUpperCase()}
2. Oxidizer Isp contribution: ${ox.isp} s
3. Oxidizer green chemistry: ${ox.green ? "YES" : "NO"}
4. Binder: ${binder.toUpperCase()}
5. Binder Isp contribution: ${bn.isp} s
6. Aluminium fuel: ${alPercent}%
7. Nano-aluminium: ${nano ? "YES (3-5× burn rate enhancement)" : "NO"}
8. Total formulated Isp: ${totalIsp} s
9. Sensitivity level: ${sensitivity}
10. Green score: ${greenScore}%

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 — SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?`,
    [oxidizer, ox, binder, bn, alPercent, nano, totalIsp, sensitivity, greenScore],
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={320} height={150} maxWidth={320} />
      <PillRow>
        <Pill active={oxidizer === "ap"} onClick={() => setOxidizer("ap")} color={T.accent}>
          AP
        </Pill>
        <Pill active={oxidizer === "an"} onClick={() => setOxidizer("an")} color={T.green}>
          AN ♻
        </Pill>
        <Pill active={oxidizer === "adn"} onClick={() => setOxidizer("adn")} color={T.purple}>
          ADN ♻
        </Pill>
        <Pill active={oxidizer === "hmx"} onClick={() => setOxidizer("hmx")} color={T.red}>
          HMX
        </Pill>
      </PillRow>
      <PillRow>
        <Pill active={binder === "htpb"} onClick={() => setBinder("htpb")} color={T.gold}>
          HTPB
        </Pill>
        <Pill active={binder === "gap"} onClick={() => setBinder("gap")} color={T.orange}>
          GAP
        </Pill>
        <Pill active={binder === "pban"} onClick={() => setBinder("pban")} color={T.gray}>
          PBAN
        </Pill>
        <Pill active={nano} onClick={() => setNano(!nano)} color={T.gold}>
          {nano ? "Nano ●" : "Nano ○"}
        </Pill>
      </PillRow>
      <Slider label="Aluminium %" value={alPercent} onChange={setAlPercent} min={0} max={30} unit="%" color={T.gray} />
      <DataRow>
        <DataBox label="Isp" value={totalIsp} unit="s" color={T.accent} />
        <DataBox label="Density" value={density.toFixed(2)} unit="g/cc" color={T.gold} />
        <DataBox
          label="Sensitivity"
          value={sensitivity}
          color={sensitivity === "HIGH" ? T.red : sensitivity === "MED" ? T.gold : T.green}
        />
        <DataBox label="Green" value={`${greenScore}%`} color={greenScore > 50 ? T.green : T.orange} />
      </DataRow>
      <InfoBox>
        <strong style={{ color: T.purple }}>Formulation:</strong> Oxidizer ({oxidizer.toUpperCase()}) + Binder (
        {binder.toUpperCase()}) + Al fuel. {ox.green ? "♻ Green oxidizer — reduced HCl emissions." : ""}{" "}
        {nano ? "Nano-Al increases burn rate 3-5× via surface area." : ""} HEMRL leads India's energetic materials
        synthesis.
      </InfoBox>
      <InfoBox color={T.orange}>
        <strong>HEM Safety Classification:</strong><br/>
        <span style={{ fontSize: 10 }}>
          AP (oxidizer): UN Class 5.1 Oxidizer — hygroscopic, store in sealed containers.<br/>
          Al powder: UN Class 4.1 Flammable Solid — static-sensitive, ground all equipment.<br/>
          HTPB binder: non-hazardous alone, crosslinks with IPDI (isocyanate — respiratory hazard).<br/>
          Mixed propellant: UN Class 1.3C — mass fire hazard. HEMRL safety protocols apply.
        </span>
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.purple} />
      <ExportBtn
        simId="propellant_chemistry"
        getData={() => ({ oxidizer, binder, alPercent, nano, totalIsp, density })}
        color={T.purple}
      />
    </div>
  );
}

import { useState, useMemo, useCallback } from "react";
import { T, TECH_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas } from "../components";
import { AIInsight } from "../components/AIInsight";


export default function ReactiveArmorSim() {
  const [armorType, setArmorType] = useState("era");
  const [obliquity, setObliquity] = useState(30);
  const [threat, setThreat] = useState("heat");

  // ── Physics ────────────────────────────────────────────────────────────────
  const physics = useMemo(() => {
    const baseProt = {
      era: { ke: 80, heat: 400, fragment: 150 },
      nera: { ke: 50, heat: 250, fragment: 120 },
      composite: { ke: 300, heat: 200, fragment: 250 },
    };
    const baseV50 = { era: 1200, nera: 1000, composite: 1500 };
    const threatFactor = { ke: 1.0, heat: 0.6, fragment: 1.3 };
    const armorBonus = {
      era: threat === "heat" ? 15 : 5,
      composite: threat === "ke" ? 15 : 5,
      nera: 5,
    };

    const obliqRad = (obliquity * Math.PI) / 180;
    const obliquityFactor = Math.min(4.0, 1 / Math.cos(obliqRad));

    const protEff = Math.round(baseProt[armorType][threat] * obliquityFactor);
    const V50eff = Math.round(baseV50[armorType] * obliquityFactor * threatFactor[threat]);
    const defeatPct = Math.min(99, Math.round(60 + obliquity * 0.4 + armorBonus[armorType]));

    return { protEff, V50eff, defeatPct, obliquityFactor };
  }, [armorType, obliquity, threat]);

  // ── Canvas ─────────────────────────────────────────────────────────────────
  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const canvasTheme = getCanvasTheme();

      // Background
      const bgGlow = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, W / 2);
      bgGlow.addColorStop(0, `${T.accent}08`);
      bgGlow.addColorStop(1, "transparent");
      ctx.fillStyle = canvasTheme.panelFill;
      ctx.fillRect(0, 0, W, H);
      ctx.fillStyle = bgGlow;
      ctx.fillRect(0, 0, W, H);

      // ── Colour helpers ──────────────────────────────────────────────────
      const reactiveColor = armorType === "era" ? T.red : armorType === "nera" ? T.accent : "#2ecc71";

      // ── Draw angled armor stack (centre) ────────────────────────────────
      const plateCx = W / 2 - 10;
      const plateCy = H / 2;
      const plateW = 28;
      const plateH = H * 0.72;
      const obliqRad = (obliquity * Math.PI) / 180;

      ctx.save();
      ctx.translate(plateCx, plateCy);
      ctx.rotate(-obliqRad);

      // Outer steel layer
      ctx.fillStyle = "#556070";
      ctx.strokeStyle = `${T.gray}60`;
      ctx.lineWidth = 1;
      ctx.fillRect(-plateW / 2 - 8, -plateH / 2, 8, plateH);
      ctx.strokeRect(-plateW / 2 - 8, -plateH / 2, 8, plateH);

      // Reactive / intermediate layer
      const shimmerShift = Math.sin(frame * 0.05) * 50;
      const reactGrad = ctx.createLinearGradient(-plateW / 2, 0 + shimmerShift, plateW / 2, 0 - shimmerShift);
      reactGrad.addColorStop(0, `${reactiveColor}55`);
      reactGrad.addColorStop(0.5, reactiveColor);
      reactGrad.addColorStop(1, `${reactiveColor}55`);
      ctx.fillStyle = reactGrad;
      ctx.strokeStyle = `${reactiveColor}99`;
      ctx.fillRect(-plateW / 2, -plateH / 2, plateW, plateH);
      ctx.strokeRect(-plateW / 2, -plateH / 2, plateW, plateH);

      // ERA tile markings
      if (armorType === "era") {
        ctx.strokeStyle = `${T.red}60`;
        ctx.lineWidth = 0.8;
        for (let y = -plateH / 2 + 14; y < plateH / 2 - 5; y += 14) {
          ctx.beginPath();
          ctx.moveTo(-plateW / 2, y);
          ctx.lineTo(plateW / 2, y);
          ctx.stroke();
          ctx.fillStyle = `rgba(255, 69, 58, ${0.1 + Math.sin(frame * 0.1 + y)*0.1})`;
          ctx.fillRect(-plateW / 2, y - 10, plateW, 10);
        }
      }
      // NERA wavy lines
      if (armorType === "nera") {
        ctx.strokeStyle = `${T.accent}50`;
        ctx.lineWidth = 1;
        for (let y = -plateH / 2 + 10; y < plateH / 2 - 5; y += 10) {
          ctx.beginPath();
          for (let x = -plateW / 2; x <= plateW / 2; x += 4) {
            const wave = Math.sin((x + y) * 0.4 - frame * 0.1) * 2;
            x === -plateW / 2 ? ctx.moveTo(x, y + wave) : ctx.lineTo(x, y + wave);
          }
          ctx.stroke();
        }
      }
      // Composite ceramic fracture lines
      if (armorType === "composite") {
        ctx.strokeStyle = "#2ecc7150";
        ctx.lineWidth = 0.7;
        const hexPts = [
          [-8, -plateH / 2 + 20],
          [4, -plateH / 2 + 30],
          [8, -plateH / 2 + 50],
          [-4, -plateH / 2 + 60],
          [-8, -plateH / 2 + 80],
          [6, -plateH / 2 + 90],
        ];
        hexPts.forEach(([hx, hy], i) => {
          if (i < hexPts.length - 1) {
            ctx.beginPath();
            ctx.moveTo(hx, hy);
            ctx.lineTo(hexPts[i + 1][0], hexPts[i + 1][1]);
            ctx.stroke();
          }
        });
      }

      // Inner steel backing
      ctx.fillStyle = "#455060";
      ctx.strokeStyle = `${T.gray}50`;
      ctx.lineWidth = 1;
      ctx.fillRect(plateW / 2, -plateH / 2, 8, plateH);
      ctx.strokeRect(plateW / 2, -plateH / 2, 8, plateH);

      ctx.restore();

      // ── Incoming threat (from left) ─────────────────────────────────────
      const threatEndX = plateCx - Math.cos(obliqRad) * (plateW / 2 + 8) - 10;
      const threatY = plateCy + Math.sin(obliqRad) * 0;

      const approach = (frame % 300) / 300; 
      const offsetX = -100 + approach * 100;
      const tX = threatEndX + offsetX;

      if (threat === "ke") {
        // Long thin APFSDS rod
        ctx.shadowBlur = 8;
        ctx.shadowColor = T.cyan;
        ctx.fillStyle = T.cyan;
        ctx.fillRect(40 + offsetX, threatY - 3, tX - (40 + offsetX), 6);
        ctx.shadowBlur = 0;
        // Fin stub
        ctx.fillStyle = `${T.cyan}88`;
        ctx.fillRect(40 + offsetX, threatY - 8, 14, 16);
      } else if (threat === "heat") {
        // HEAT projectile nose
        ctx.fillStyle = T.orange;
        ctx.strokeStyle = `${T.orange}aa`;
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.moveTo(tX, threatY);
        ctx.lineTo(tX - 20, threatY - 10);
        ctx.lineTo(tX - 50, threatY - 10);
        ctx.lineTo(tX - 50, threatY + 10);
        ctx.lineTo(tX - 20, threatY + 10);
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
        // Standoff probe
        ctx.strokeStyle = T.yellow ?? "#f4c430";
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(tX, threatY);
        ctx.lineTo(tX + 18, threatY);
        ctx.stroke();
      } else {
        // Irregular fragment polygon
        ctx.fillStyle = T.gray;
        ctx.strokeStyle = "#88a0b8";
        ctx.lineWidth = 1;
        ctx.beginPath();
        const fpts = [
          [tX - 18, threatY - 9],
          [tX - 8, threatY - 14],
          [tX, threatY - 4],
          [tX - 4, threatY + 10],
          [tX - 16, threatY + 8],
        ];
        fpts.forEach(([fx, fy], i) => (i === 0 ? ctx.moveTo(fx, fy) : ctx.lineTo(fx, fy)));
        ctx.closePath();
        ctx.fill();
        ctx.stroke();
      }

      // ── Impact effects ──────────────────────────────────────────────────
      const impactX = plateCx - Math.cos(obliqRad) * 4;
      const impactY = plateCy;

      if (armorType === "era") {
        // Reactive tiles flying out — deterministic rotation per tile index
        const tileOffsets = [
          [-16, -22],
          [10, -18],
          [-8, 18],
          [14, 20],
          [-22, 4],
        ];
        tileOffsets.forEach(([dx, dy], tileIdx) => {
          ctx.save();
          ctx.translate(impactX + dx, impactY + dy);
          ctx.rotate(prng(0, tileIdx) * 0.5);
          ctx.fillStyle = T.orange;
          ctx.shadowBlur = 6;
          ctx.shadowColor = T.orange;
          ctx.fillRect(-4, -4, 8, 8);
          ctx.shadowBlur = 0;
          ctx.restore();
        });
      } else if (armorType === "nera") {
        // Bulging layer (ellipse outline)
        ctx.strokeStyle = `${T.accent}80`;
        ctx.lineWidth = 2;
        ctx.setLineDash([3, 3]);
        ctx.beginPath();
        ctx.ellipse(impactX, impactY, 18, 35, -obliqRad, 0, Math.PI * 2);
        ctx.stroke();
        ctx.setLineDash([]);
      } else {
        // Ceramic fracture radial lines
        ctx.strokeStyle = `#2ecc71aa`;
        ctx.lineWidth = 1;
        for (let a = 0; a < Math.PI * 2; a += Math.PI / 5) {
          ctx.beginPath();
          ctx.moveTo(impactX, impactY);
          ctx.lineTo(impactX + Math.cos(a) * 22, impactY + Math.sin(a) * 22);
          ctx.stroke();
        }
      }

      // ── Residual penetration indicator (right) ──────────────────────────
      const residualX = plateCx + Math.cos(obliqRad) * (plateW / 2 + 18) + 12;
      const residualMaxLen = 60;
      const residualFrac = Math.max(0, 1 - physics.defeatPct / 100);
      const residualLen = residualFrac * residualMaxLen;

      ctx.font = `700 8px ${TECH_FONT}`;
      ctx.fillStyle = T.dimText ?? "#88a0b8";
      ctx.textAlign = "left";
      ctx.fillText("RESIDUAL", residualX + 2, plateCy - 38);

      ctx.strokeStyle = `${T.gray}40`;
      ctx.lineWidth = 6;
      ctx.lineCap = "round";
      ctx.beginPath();
      ctx.moveTo(residualX, plateCy - 30);
      ctx.lineTo(residualX, plateCy - 30 + residualMaxLen);
      ctx.stroke();

      if (residualLen > 0) {
        ctx.strokeStyle = residualFrac > 0.4 ? T.red : T.orange;
        ctx.shadowBlur = 8;
        ctx.shadowColor = ctx.strokeStyle;
        ctx.lineWidth = 4;
        ctx.beginPath();
        ctx.moveTo(residualX, plateCy - 30);
        ctx.lineTo(residualX, plateCy - 30 + residualLen);
        ctx.stroke();
        ctx.shadowBlur = 0;
      }
      ctx.lineCap = "butt";

      // ── Labels ────────────────────────────────────────────────────────────
      ctx.textAlign = "left";
      ctx.font = `900 9px ${TECH_FONT}`;
      ctx.fillStyle = T.accent;
      ctx.fillText("ARMOR PROTECTION MODEL", 8, 14);

      ctx.font = `700 8px ${TECH_FONT}`;
      ctx.fillStyle = reactiveColor;
      ctx.fillText(armorType.toUpperCase(), plateCx - 14, 14);

      ctx.fillStyle = T.gray;
      ctx.fillText(`OBL: ${obliquity}°`, plateCx - 20, H - 8);

      ctx.fillStyle = T.cyan;
      ctx.textAlign = "right";
      ctx.fillText(threat.toUpperCase(), W - 8, 14);
    },
    [armorType, obliquity, threat, physics],
    { animate: true }
  );

  // ── AI prompt ──────────────────────────────────────────────────────────────
  const buildPrompt = useCallback(
    () =>
      `Ballistic protection and armor engineering simulation — current parameters:
ROLE: "You are an expert in ballistic protection, armor engineering, and DRDO vehicle protection programs. You have deep knowledge of ERA, NERA, composite armors, and Indian armored vehicle development."

PARAMETERS (numbered):
1. Armor type: ${armorType.toUpperCase()} (${armorType === "era" ? "Explosive Reactive Armor" : armorType === "nera" ? "Non-Explosive Reactive Armor" : "Ceramic-metal composite laminate"})
2. Obliquity angle: ${obliquity}°
3. Threat type: ${threat.toUpperCase()} (${threat === "ke" ? "KE penetrator / APFSDS" : threat === "heat" ? "HEAT shaped charge jet" : "Artillery fragment"})
4. Effective protection: ${physics.protEff} mm RHAe
5. Ballistic limit (V50): ${physics.V50eff} m/s
6. Defeat probability: ${physics.defeatPct}%
7. Obliquity factor (sec θ): ${physics.obliquityFactor.toFixed(2)}x

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Evaluate the protection effectiveness. Is the obliquity angle optimal? How does the armor type interact with this threat category?
Part 2 — SAFETY & RISK: What are the failure modes for this armor configuration? What are the survivability risks for the crew at this protection level?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO armor programs? Reference specific Indian systems (e.g., Arjun MBT Kanchan armor, FRCV program, BMP-II upgrades, DRDO ERA tiles) where applicable. What are India's current capabilities and development priorities in vehicle protection?`,
    [armorType, obliquity, threat, physics],
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={220} maxWidth={460} />

      {/* Armor type */}
      <PillRow>
        <Pill active={armorType === "era"} onClick={() => setArmorType("era")}>
          💥 ERA
        </Pill>
        <Pill active={armorType === "nera"} onClick={() => setArmorType("nera")}>
          🔵 NERA
        </Pill>
        <Pill active={armorType === "composite"} onClick={() => setArmorType("composite")}>
          🟢 Composite
        </Pill>
      </PillRow>

      {/* Threat type */}
      <PillRow>
        <Pill active={threat === "ke"} onClick={() => setThreat("ke")}>
          ⚡ KE (APFSDS)
        </Pill>
        <Pill active={threat === "heat"} onClick={() => setThreat("heat")}>
          🎯 HEAT
        </Pill>
        <Pill active={threat === "fragment"} onClick={() => setThreat("fragment")}>
          💢 Fragment
        </Pill>
      </PillRow>

      <Slider
        label="Obliquity Angle"
        value={obliquity}
        onChange={(v) => setObliquity(v)}
        min={0}
        max={75}
        step={1}
        unit="°"
        color={T.cyan}
      />

      <DataRow>
        <DataBox label="Protection" value={physics.protEff} unit="mm RHAe" color={T.accent} />
        <DataBox label="V50" value={physics.V50eff} unit="m/s" color={T.green} />
        <DataBox
          label="Defeat %"
          value={`${physics.defeatPct}%`}
          color={physics.defeatPct > 80 ? T.green : physics.defeatPct > 50 ? T.orange : T.red}
        />
        <DataBox label="Obliquity" value={obliquity} unit="°" color={T.cyan} />
      </DataRow>

      <InfoBox color={T.accent}>
        <strong style={{ color: T.accent }}>DRDO's Kanchan</strong> composite armor (Arjun MBT) provides multi-threat
        protection. ERA tiles (Contact-5 type) are effective against HEAT jets but less so vs KE rods. NERA offers
        reusable protection without explosive risk.
      </InfoBox>

      <AIInsight buildPrompt={buildPrompt} color={T.accent} />
    </div>
  );
}

import { useState, useMemo, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";

import { MISSILE_DB } from "../data/missileDB";

export default function ScramjetSim() {
  const related = MISSILE_DB.filter((m) => m.relatedSimId === "scramjet");
  const [mach, setMach] = useState(6);
  const [propMode, setPropMode] = useState("scramjet");
  const [fuelType, setFuelType] = useState("hydrogen");
  const [altitude, setAltitude] = useState(25);
  const [cooling, setCooling] = useState(true);

  const handlePropMode = (mode) => {
    setPropMode(mode);
    const range = { scramjet: [4, 12], ramjet: [1.5, 5], irrt: [1.5, 4] }[mode];
    if (mach < range[0] || mach > range[1]) {
      setMach((range[0] + range[1]) / 2);
    }
  };

  const temp = useMemo(() => Math.round(288 * (1 + 0.2 * mach * mach)), [mach]);
  const { thrustN, eta, Pt2, Ve, Tcomb, T_atm } = useMemo(() => {
    const fuelHeat = fuelType === "hydrogen" ? 2200 : fuelType === "jp7" ? 1400 : 1600;
    const V0 = mach * 340;
    const P_atm = 101325 * Math.exp(-altitude / 8.5);
    const T_atm = 288 - 6.5 * Math.min(altitude, 11);
    const Pt2 = P_atm * Math.pow(1 + 0.2 * mach * mach, 3.5);
    const mdot = 0.5 + mach * 0.3;

    let thrustN = 0, Ve = 0, eta = 0, Tcomb = 0;

    if (propMode === "scramjet") {
      Tcomb = temp + fuelHeat;
      Ve = Math.sqrt(2 * 1005 * Tcomb * (1 - Math.pow(P_atm / Pt2, 0.286)));
      const F_sp = Ve - V0;
      thrustN = Math.max(0, Math.round((F_sp * mdot) / 1000));
      eta = Math.round((1 - T_atm / Tcomb) * 100);
    } else if (propMode === "ramjet") {
      Tcomb = temp + fuelHeat * 0.8;
      Ve = Math.sqrt(2 * 1005 * Tcomb * 0.6);
      const ramjetEta = mach < 2 ? 0.4 : mach > 4 ? 0.3 : 0.7;
      thrustN = Math.max(0, Math.round((Ve * ramjetEta - V0) * mdot / 1000));
      eta = Math.round((1 - T_atm / Tcomb) * 100 * ramjetEta);
    } else if (propMode === "irrt") {
      const irrtFuelHeat = { hydrogen: 1800, jp7: 1200, ethylene: 1400 }[fuelType];
      Tcomb = temp + irrtFuelHeat;
      const irrtEta = 0.55;
      Ve = Math.sqrt(2 * 1005 * Tcomb * irrtEta);
      thrustN = Math.max(0, Math.round((Ve - V0) * mdot * 0.8 / 1000));
      eta = Math.round((1 - T_atm / Tcomb) * 100 * irrtEta);
    }
    return { thrustN, eta, Pt2, Ve, Tcomb, T_atm };
  }, [mach, fuelType, altitude, temp, propMode]);
  const wallT = useMemo(() => {
    const base = temp * 0.6;
    return Math.round(cooling ? base * 0.35 : base);
  }, [temp, cooling]);

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const cy = H / 2;

      // Canvas Backgrounds
      const theme = getCanvasTheme();
      const bgGrad = ctx.createRadialGradient(W / 2, cy, 0, W / 2, cy, W);
      bgGrad.addColorStop(0, theme.canvasBackground);
      bgGrad.addColorStop(1, theme.canvasSurface);
      ctx.fillStyle = bgGrad;
      ctx.fillRect(0, 0, W, H);

      ctx.font = `900 12px ${TECH_FONT}`;
      ctx.fillStyle = T.white;
      ctx.textAlign = "center";
      ctx.fillText(propMode === "scramjet" ? "SCRAMJET" : propMode === "ramjet" ? "RAMJET" : "INTEGRAL RAM ROCKET", W/2, 20);

      // Inlet Diffuser
      ctx.fillStyle = "#2D3748";
      ctx.strokeStyle = `${T.accent}40`;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(20, cy - 40);
      ctx.lineTo(80, cy - 20);
      ctx.lineTo(80, cy + 20);
      ctx.lineTo(20, cy + 40);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();

      if (propMode === "scramjet") {
        // Scramjet Combustor
        ctx.fillStyle = "#1A202C";
        ctx.fillRect(80, cy - 20, 180, 40);
        ctx.strokeRect(80, cy - 20, 180, 40);

        const flameGrad = ctx.createLinearGradient(130, 0, 260, 0);
        flameGrad.addColorStop(0, T.white);
        flameGrad.addColorStop(0.2, T.orange);
        flameGrad.addColorStop(1, "transparent");

        ctx.fillStyle = flameGrad;
        ctx.globalAlpha = 0.6 + prng(frame, 1) * 0.2;
        ctx.beginPath();
        ctx.roundRect(130, cy - 15, 130 + mach * 5, 30, 4);
        ctx.fill();
        ctx.globalAlpha = 1;

        for (let i = 0; i < 12; i++) {
          const px = 140 + prng(frame, i * 3) * 150;
          const py = cy + (prng(frame, i * 3 + 1) - 0.5) * 25;
          ctx.fillStyle = `rgba(255, 200, 100, ${prng(frame, i * 3 + 2) * 0.8})`;
          ctx.fillRect(px, py, 4 + prng(frame, i * 3 + 2) * 10, 1);
        }

        if (cooling) {
          ctx.shadowBlur = 10;
          ctx.shadowColor = T.cyan;
          ctx.strokeStyle = `${T.cyan}88`;
          ctx.setLineDash([5, 5]);
          ctx.strokeRect(100, cy - 25, 160, 50);
          ctx.setLineDash([]);
          ctx.shadowBlur = 0;
        }

        // Expansion Nozzle
        ctx.fillStyle = "#2D3748";
        ctx.beginPath();
        ctx.moveTo(260, cy - 20); ctx.lineTo(340, cy - 45); ctx.lineTo(340, cy + 45); ctx.lineTo(260, cy + 20);
        ctx.closePath(); ctx.fill(); ctx.stroke();

        ctx.font = `900 10px ${TECH_FONT}`;
        ctx.textAlign = "center";
        ctx.fillStyle = T.cyan; ctx.fillText("SUPERSONIC COMBUSTOR", 170, cy + 55);

      } else if (propMode === "ramjet") {
        // Ramjet Diffuser step to Subsonic Combustor
        ctx.fillStyle = "#1A202C";
        ctx.fillRect(80, cy - 35, 180, 70);
        ctx.strokeRect(80, cy - 35, 180, 70);

        // Flame holders (V-gutters)
        ctx.fillStyle = T.gray;
        ctx.beginPath(); ctx.moveTo(110, cy); ctx.lineTo(130, cy - 15); ctx.lineTo(130, cy + 15); ctx.fill();

        const flameGrad = ctx.createLinearGradient(130, 0, 260, 0);
        flameGrad.addColorStop(0, T.white); flameGrad.addColorStop(0.3, T.orange); flameGrad.addColorStop(1, "transparent");
        ctx.fillStyle = flameGrad;
        ctx.globalAlpha = 0.8 + prng(frame, 1) * 0.2;
        ctx.beginPath(); ctx.arc(130, cy, 20, -Math.PI/2.5, Math.PI/2.5); ctx.arc(260, cy, 30, Math.PI/2.5, -Math.PI/2.5); ctx.fill();
        ctx.globalAlpha = 1;

        // Expansion Nozzle
        ctx.fillStyle = "#2D3748";
        ctx.beginPath();
        ctx.moveTo(260, cy - 35); ctx.lineTo(340, cy - 15); ctx.lineTo(340, cy + 15); ctx.lineTo(260, cy + 35);
        ctx.closePath(); ctx.fill(); ctx.stroke();

        ctx.font = `900 10px ${TECH_FONT}`;
        ctx.textAlign = "center";
        ctx.fillStyle = T.orange; ctx.fillText("SUBSONIC COMBUSTOR", 170, cy + 55);

      } else if (propMode === "irrt") {
        // IRRT Combustor Walls (Solid Fuel Grain lining)
        ctx.fillStyle = "#1A202C";
        ctx.fillRect(80, cy - 35, 180, 70);

        ctx.fillStyle = "#A0522D"; // Fuel Grain
        ctx.fillRect(80, cy - 35, 180, 15);
        ctx.fillRect(80, cy + 20, 180, 15);

        ctx.strokeRect(80, cy - 35, 180, 70);

        const flameGrad = ctx.createLinearGradient(120, 0, 260, 0);
        flameGrad.addColorStop(0, T.yellow); flameGrad.addColorStop(0.4, T.orange); flameGrad.addColorStop(1, "transparent");
        ctx.fillStyle = flameGrad;
        ctx.globalAlpha = 0.5 + prng(frame, 1) * 0.3;
        ctx.fillRect(100, cy - 20, 160, 40);
        ctx.globalAlpha = 1;

        // Expansion Nozzle
        ctx.fillStyle = "#2D3748";
        ctx.beginPath();
        ctx.moveTo(260, cy - 35); ctx.lineTo(340, cy - 20); ctx.lineTo(340, cy + 20); ctx.lineTo(260, cy + 35);
        ctx.closePath(); ctx.fill(); ctx.stroke();

        ctx.font = `900 10px ${TECH_FONT}`;
        ctx.textAlign = "center";
        ctx.fillStyle = T.green; ctx.fillText("SOLID FUEL GRAIN BURN", 170, cy + 55);
      }

      // Exhaust Expansion Fan
      const exhaustGrad = ctx.createLinearGradient(340, 0, 410, 0);
      exhaustGrad.addColorStop(0, `${T.accent}44`); exhaustGrad.addColorStop(1, "transparent");
      ctx.fillStyle = exhaustGrad;
      ctx.beginPath(); ctx.moveTo(340, cy - (propMode === "scramjet" ? 40 : 15)); ctx.lineTo(410, cy - 60); ctx.lineTo(410, cy + 60); ctx.lineTo(340, cy + (propMode === "scramjet" ? 40 : 15)); ctx.fill();

      // Inlet Shockwaves (Aero-Heating)
      if (mach > 5) {
        ctx.shadowBlur = 10; ctx.shadowColor = T.red; ctx.strokeStyle = `rgba(255, 69, 58, 0.8)`; ctx.lineWidth = 2;
        ctx.beginPath(); ctx.moveTo(20, cy - 40); ctx.lineTo(25, cy - 41); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(20, cy + 40); ctx.lineTo(25, cy + 41); ctx.stroke();
        ctx.shadowBlur = 0;
      }
      ctx.strokeStyle = `${T.cyan}${Math.floor(20 + mach * 10).toString(16)}`; ctx.lineWidth = 1;
      for (let i = 0; i < 3; i++) {
        ctx.beginPath(); ctx.moveTo(20, cy - 40); ctx.lineTo(60 + i * 15, cy - 10 + i * 5); ctx.stroke();
        ctx.beginPath(); ctx.moveTo(20, cy + 40); ctx.lineTo(60 + i * 15, cy + 10 - i * 5); ctx.stroke();
      }

      // Mach Vector Overlay
      ctx.strokeStyle = T.white;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(10, cy);
      ctx.lineTo(40, cy);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(40, cy);
      ctx.lineTo(35, cy - 3);
      ctx.moveTo(40, cy);
      ctx.lineTo(35, cy + 3);
      ctx.stroke();
      ctx.font = `bold 9px ${MONO_FONT}`;
      ctx.fillStyle = T.white;
      ctx.fillText(`M${mach}`, 10, cy - 8);
    },
    [mach, fuelType, cooling],
    { animate: true },
  );

  const buildPrompt = useCallback(
    () =>
      `Air-breathing propulsion simulation — current parameters:
ROLE: "You are an expert in hypersonic and ramjet propulsion. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Propulsion mode: ${propMode.toUpperCase()}
2. Flight Mach number: ${mach}
3. Fuel type: ${fuelType}
4. Altitude: ${altitude} km
5. Active regenerative cooling: ${cooling ? "YES" : "NO"}
6. Stagnation temperature: ${temp} K
7. Thermal efficiency: ${eta} %
8. Inlet total pressure: ${(Pt2 / 1e6).toFixed(2)} MPa
9. Exit velocity (Ve): ${Math.round(Ve)} m/s
10. Combustor total temperature: ${Tcomb} K
11. Net thrust: ${thrustN} kN

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash, HSTDV) where applicable. What are India's current capabilities and gaps in this domain?
Related Indian systems: ${related.map((m) => m.name).join(", ")}`,
    [propMode, mach, fuelType, altitude, cooling, temp, eta, Pt2, Ve, Tcomb, thrustN, related],
  );

  const modeInfo = {
    scramjet: "Supersonic combustion at M>5. DRDO HSTDV achieved Mach 6 flight (2020) and 1000s ground test (Apr 2025).",
    ramjet: "Subsonic combustion, M1.5-5 range. Powers Akash SAM (ramjet-rocket) and BrahMos cruise stage (liquid ramjet with JP-10).",
    irrt: "Integral Ram Rocket uses a solid fuel grain that burns with ram air — no liquid fuel system needed. PL8 speaker Dr. BS Subhash Chandran (DRDL) leads India's IRRT development for next-gen SAMs and cruise missiles.",
  };
  const machRange = { scramjet: [4, 12], ramjet: [1.5, 5], irrt: [1.5, 4] }[propMode];

  return (
    <div>
      <PillRow>
        <Pill active={propMode === "scramjet"} onClick={() => handlePropMode("scramjet")} color={T.cyan}>Scramjet</Pill>
        <Pill active={propMode === "ramjet"} onClick={() => handlePropMode("ramjet")} color={T.orange}>Ramjet</Pill>
        <Pill active={propMode === "irrt"} onClick={() => handlePropMode("irrt")} color={T.green}>IRRT</Pill>
      </PillRow>
      <SimCanvas canvasRef={canvasRef} width={420} height={130} maxWidth={420} />
      <PillRow>
        <Pill active={fuelType === "hydrogen"} onClick={() => setFuelType("hydrogen")} color={T.green}>
          {propMode === "irrt" ? "Boron-HTPB" : "Hydrogen"}
        </Pill>
        <Pill active={fuelType === "jp7"} onClick={() => setFuelType("jp7")} color={T.orange}>
          {propMode === "irrt" ? "Carbon-Metal" : "JP-7"}
        </Pill>
        <Pill active={fuelType === "ethylene"} onClick={() => setFuelType("ethylene")} color={T.cyan}>
          {propMode === "irrt" ? "AP-HTPB" : "Ethylene"}
        </Pill>
        {propMode === "scramjet" && (
          <Pill active={cooling} onClick={() => setCooling(!cooling)} color={T.cyan}>
            {cooling ? "Cooling ON" : "Cooling OFF"}
          </Pill>
        )}
      </PillRow>
      <Slider
        label="Mach Number"
        value={mach}
        onChange={setMach}
        min={machRange[0]}
        max={machRange[1]}
        step={0.5}
        unit=""
        color={T.orange}
      />
      <Slider label="Altitude" value={altitude} onChange={setAltitude} min={0} max={30} unit=" km" color={T.accent} />
      <DataRow>
        <DataBox label="Stagnation T" value={temp} unit="K" color={temp > 2500 ? T.red : T.orange} />
        <DataBox label="η_thermal" value={eta} unit="%" color={T.green} />
        <DataBox label="Inlet Pt" value={(Pt2 / 1e6).toFixed(1)} unit="MPa" color={T.purple} />
        <DataBox label="Ve" value={Math.round(Ve)} unit="m/s" color={T.cyan} />
        <DataBox label="Thrust" value={thrustN} unit="kN" color={T.green} />
        {propMode === "scramjet" && <DataBox label="Wall T" value={wallT} unit="K" color={wallT > 800 ? T.red : T.cyan} />}
      </DataRow>
      <InfoBox>
        <strong style={{ color: T.cyan }}>{propMode.toUpperCase()}:</strong> {modeInfo[propMode]}
        {propMode === "scramjet" && !cooling && " ⚠ Without cooling, walls exceed material limits above Mach 7."}
        {related.length > 0 && (
          <div style={{ marginTop: 8, borderTop: `1px solid ${T.glassBorder}`, paddingTop: 8 }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: T.accent, marginBottom: 4 }}>
              INDIAN SYSTEMS USING THIS TECHNOLOGY:
            </div>
            {related.map((m) => (
              <div key={m.id} style={{ fontSize: 10, color: T.gray, marginBottom: 2 }}>
                {m.image_emoji} <strong style={{ color: T.white }}>{m.name}</strong>
                {" — "}{m.propulsion.stages} | {m.performance.range}
                {m.sources[0] && (
                  <a href={m.sources[0].url} target="_blank" rel="noopener noreferrer"
                     style={{ color: T.accent, marginLeft: 4, fontSize: 9 }}>
                    [source]
                  </a>
                )}
              </div>
            ))}
          </div>
        )}
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.cyan} />
      <ExportBtn
        simId="scramjet"
        getData={() => ({ mach, fuelType, altitude, cooling, thrustN, eta, Ve })}
        color={T.cyan}
      />
    </div>
  );
}

import { useState, useMemo, useCallback } from "react";
import { T, TECH_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";


export default function ShapedChargeSim() {
  const [liner, setLiner] = useState("copper");
  const [coneAngle, setConeAngle] = useState(42);
  const [standoff, setStandoff] = useState(3);
  const [explosive, setExplosive] = useState("rdx");

  // ── Physics ────────────────────────────────────────────────────────────────
  const physics = useMemo(() => {
    const VoDMap = { rdx: 8750, hmx: 9100 };
    const linerDensityMap = { copper: 8960, tantalum: 16650, steel: 7850 };

    const VoD = VoDMap[explosive];
    const linerDensity = linerDensityMap[liner];
    const halfAngleRad = (coneAngle * Math.PI) / 360;

    // Munroe-effect jet & slug velocities
    const Vjet = VoD * Math.cos(halfAngleRad);
    const Vslug = VoD * Math.sin(halfAngleRad) * 0.3;

    // Birkhoff-Eichelberger penetration
    const linerLength = 80 / Math.tan(halfAngleRad); // mm
    const P = linerLength * Math.sqrt(linerDensity / 7850);

    // Standoff optimality factor
    const rawFactor = 1 - 0.05 * Math.pow(standoff - 3, 2);
    const standoffFactor = Math.min(1.0, Math.max(0.3, rawFactor));
    const Peff = Math.round(P * standoffFactor);

    return { Vjet, Vslug, P, standoffFactor, Peff, linerDensity };
  }, [liner, coneAngle, standoff, explosive]);

  // ── Canvas ─────────────────────────────────────────────────────────────────
  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const canvasTheme = getCanvasTheme();

      // Background
      const bgGlow = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, W / 2);
      bgGlow.addColorStop(0, `${T.red}08`);
      bgGlow.addColorStop(1, "transparent");
      ctx.fillStyle = canvasTheme.panelFill;
      ctx.fillRect(0, 0, W, H);
      ctx.fillStyle = bgGlow;
      ctx.fillRect(0, 0, W, H);

      // ── Colour helpers ────────────────────────────────────────────────────
      const linerColor = liner === "copper" ? "#b87333" : liner === "tantalum" ? "#8899aa" : "#aab0b8";
      const explColor = explosive === "rdx" ? "#c0392b" : "#8e44ad";

      // ── Shaped charge body (left-centre) ──────────────────────────────────
      const bodyX = 30,
        bodyY = 30,
        bodyW = 100,
        bodyH = H - 60;
      const cx = bodyX + bodyW / 2;

      // Detonation wave front propagates slowly down the charge
      const waveCycle = (frame % 200) / 200;
      const waveY = bodyY + waveCycle * bodyH;

      // Cylindrical explosive body
      const bodyGrad = ctx.createLinearGradient(bodyX, 0, bodyX + bodyW, 0);
      bodyGrad.addColorStop(0, `${explColor}55`);
      bodyGrad.addColorStop(0.5, explColor);
      bodyGrad.addColorStop(1, `${explColor}55`);
      ctx.fillStyle = bodyGrad;
      ctx.strokeStyle = `${T.red}80`;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.roundRect(bodyX, bodyY, bodyW, bodyH, 6);
      ctx.fill();
      ctx.stroke();

      // Draw Wave Front
      ctx.fillStyle = T.yellow;
      ctx.globalAlpha = 0.5 * (1-waveCycle);
      ctx.fillRect(bodyX, bodyY, bodyW, waveY - bodyY);
      ctx.globalAlpha = 1;

      // Detonator (top, red circle)
      ctx.shadowBlur = 12;
      ctx.shadowColor = T.red;
      ctx.fillStyle = T.red;
      ctx.beginPath();
      ctx.arc(cx, bodyY + 10, 7, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;

      // Conical liner (V-shape at bottom of charge)
      const halfAngleRad = (coneAngle * Math.PI) / 360;
      const coneHeight = Math.min(bodyH * 0.55, 70 / Math.tan(halfAngleRad));
      const coneBaseY = bodyY + bodyH;
      const coneHalfW = coneHeight * Math.tan(halfAngleRad);
      const coneTipX = cx;
      const coneTipY = coneBaseY - coneHeight;

      const linerGrad = ctx.createLinearGradient(cx - coneHalfW, 0, cx + coneHalfW, 0);
      linerGrad.addColorStop(0, `${linerColor}88`);
      linerGrad.addColorStop(0.5, linerColor);
      linerGrad.addColorStop(1, `${linerColor}88`);
      ctx.fillStyle = linerGrad;
      ctx.strokeStyle = `${linerColor}cc`;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(cx - coneHalfW, coneBaseY);
      ctx.lineTo(coneTipX, coneTipY);
      ctx.lineTo(cx + coneHalfW, coneBaseY);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();

      // ── Jet & slug (extending right from cone tip) ────────────────────────
      const standoffPx = Math.min(standoff * 18, W - bodyX - bodyW - 40);
      const jetStartX = cx + bodyW / 2 + 4;
      const jetY = coneTipY;
      const targetX = bodyX + bodyW + standoffPx;

      // Jet glow line
      ctx.shadowBlur = 10;
      ctx.shadowColor = linerColor;
      const jetGrad = ctx.createLinearGradient(jetStartX, 0, targetX, 0);
      jetGrad.addColorStop(0, linerColor);
      jetGrad.addColorStop(1, "transparent");
      ctx.strokeStyle = jetGrad;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(jetStartX, jetY);
      ctx.lineTo(targetX, jetY);
      ctx.stroke();

      // Jet particles drift rightward from the cone tip
      ctx.fillStyle = T.white;
      for (let i = 0; i < 15; i++) {
          const driftedX = jetStartX + ((frame * 2 + prng(frame, i) * 100) % (targetX - jetStartX));
          ctx.beginPath();
          ctx.arc(driftedX, jetY + (prng(frame, i+1) - 0.5) * 4, 1.5, 0, Math.PI*2);
          ctx.fill();
      }

      // Slug (thicker blob just behind jet head)
      const slugX = jetStartX + (targetX - jetStartX) * 0.25;
      ctx.fillStyle = linerColor;
      ctx.globalAlpha = 0.7;
      ctx.beginPath();
      ctx.ellipse(slugX, jetY, 10, 4, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
      ctx.shadowBlur = 0;

      // ── Target plate ──────────────────────────────────────────────────────
      const targetW = 18;
      const targetH = H - 40;
      const penetrationFrac = Math.min(physics.Peff / 300, 1); // normalise to 300 mm max
      const penetrationPx = penetrationFrac * targetW;

      ctx.fillStyle = "#607080";
      ctx.strokeStyle = `${T.gray}80`;
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.roundRect(targetX, 20, targetW, targetH, 3);
      ctx.fill();
      ctx.stroke();

      // Penetration channel in target
      if (physics.Peff > 0) {
        ctx.fillStyle = canvasTheme.canvasSurface;
        ctx.beginPath();
        // Penetration depth indicator pulses
        const pPulse = Math.sin(frame * 0.1) * 2;
        ctx.roundRect(targetX, jetY - 5, penetrationPx + 2 + pPulse, 10, 2);
        ctx.fill();
        // Spall glow at penetration front
        ctx.shadowBlur = 8;
        ctx.shadowColor = T.orange;
        ctx.fillStyle = T.orange;
        ctx.beginPath();
        ctx.arc(targetX + penetrationPx + pPulse, jetY, 4, 0, Math.PI * 2);
        ctx.fill();
        ctx.shadowBlur = 0;
      }

      // ── Labels ────────────────────────────────────────────────────────────
      ctx.textAlign = "left";
      ctx.font = `900 9px ${TECH_FONT}`;
      ctx.fillStyle = T.accent;
      ctx.fillText("SHAPED CHARGE", bodyX, bodyY - 6);

      ctx.fillStyle = T.gray;
      ctx.font = `600 8px ${TECH_FONT}`;
      ctx.fillText(`STANDOFF: ${standoff} CD`, jetStartX + 2, jetY - 10);

      ctx.fillStyle = linerColor;
      ctx.fillText(liner.toUpperCase() + " LINER", bodyX, coneBaseY + 12);

      ctx.fillStyle = T.red;
      ctx.fillText("DET", cx - 10, bodyY + 28);

      ctx.fillStyle = T.dimText ?? "#88a0b8";
      ctx.textAlign = "center";
      ctx.fillText("RHA TARGET", targetX + targetW / 2, 16);
    },
    [liner, coneAngle, standoff, explosive, physics],
    { animate: true }
  );

  // ── AI prompt ──────────────────────────────────────────────────────────────
  const buildPrompt = useCallback(
    () =>
      `Shaped charge warhead engineering simulation — current parameters:
ROLE: "You are an expert in shaped charge warhead engineering, terminal ballistics, and DRDO anti-armour programs. You have deep knowledge of the Munroe effect, Birkhoff-Eichelberger penetration theory, and Indian defence R&D."

PARAMETERS (numbered):
1. Liner material: ${liner} (density ${liner === "copper" ? 8960 : liner === "tantalum" ? 16650 : 7850} kg/m³)
2. Cone half-angle: ${coneAngle / 2}° (full apex angle: ${coneAngle}°)
3. Standoff distance: ${standoff} caliber diameters (CD)
4. Explosive fill: ${explosive.toUpperCase()} (VoD: ${explosive === "rdx" ? 8750 : 9100} m/s)
5. Jet velocity (Vjet): ${(physics.Vjet / 1000).toFixed(2)} km/s
6. Slug velocity: ${Math.round(physics.Vslug)} m/s
7. Effective penetration: ${physics.Peff} mm RHA
8. Standoff efficiency factor: ${(physics.standoffFactor * 100).toFixed(0)}%

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Evaluate these parameters. What jet tip velocity regime does this represent? How does liner density affect penetration? Is the standoff optimal?
Part 2 — SAFETY & RISK: What are the key failure modes (jet break-up, precursor effects, target obliquity)? What safety considerations apply to shaped charge assembly and handling?
Part 3 — INDIA-SPECIFIC CONTEXT: How do these parameters relate to DRDO shaped charge programs? Reference specific Indian systems (e.g., Nag ATGM, Arjun MBT anti-tank rounds, Helina, MPATGM) where applicable. What are India's current capabilities and development focus in shaped charge warhead technology?`,
    [liner, coneAngle, standoff, explosive, physics],
  );

  const reset = () => {};

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={220} maxWidth={460} />

      {/* Liner selector */}
      <PillRow>
        <Pill active={liner === "copper"} onClick={() => setLiner("copper")}>
          🟤 Copper
        </Pill>
        <Pill active={liner === "tantalum"} onClick={() => setLiner("tantalum")}>
          ⚫ Tantalum
        </Pill>
        <Pill active={liner === "steel"} onClick={() => setLiner("steel")}>
          🔩 Steel
        </Pill>
      </PillRow>

      {/* Cone-angle selector */}
      <PillRow>
        <Pill active={coneAngle === 42} onClick={() => setConeAngle(42)}>
          42° (narrow)
        </Pill>
        <Pill active={coneAngle === 60} onClick={() => setConeAngle(60)}>
          60° (standard)
        </Pill>
        <Pill active={coneAngle === 90} onClick={() => setConeAngle(90)}>
          90° (wide)
        </Pill>
      </PillRow>

      {/* Explosive selector */}
      <PillRow>
        <Pill active={explosive === "rdx"} onClick={() => setExplosive("rdx")}>
          RDX
        </Pill>
        <Pill active={explosive === "hmx"} onClick={() => setExplosive("hmx")}>
          HMX
        </Pill>
      </PillRow>

      <Slider
        label="Standoff Distance"
        value={standoff}
        onChange={(v) => setStandoff(v)}
        min={1}
        max={20}
        step={0.5}
        unit=" CD"
        color={T.green}
      />

      <DataRow>
        <DataBox label="Jet Velocity" value={(physics.Vjet / 1000).toFixed(1)} unit="km/s" color={T.red} />
        <DataBox label="Penetration" value={physics.Peff} unit="mm RHA" color={T.orange} />
        <DataBox label="Standoff η" value={`${(physics.standoffFactor * 100).toFixed(0)}%`} color={T.green} />
        <DataBox label="Slug V" value={Math.round(physics.Vslug)} unit="m/s" color={T.purple} />
      </DataRow>

      <InfoBox color={T.red}>
        Shaped charges use the <strong style={{ color: T.red }}>Munroe effect</strong> — explosive-driven metal liner
        collapse forms a hypervelocity jet. DRDO's anti-tank munitions (Nag ATGM) use copper-lined shaped charges.
        Optimal standoff is <strong>2–4 CD</strong>.
      </InfoBox>

      <AIInsight buildPrompt={buildPrompt} color={T.red} />
      <ExportBtn
        simId="shaped_charge"
        getData={() => ({
          liner,
          coneAngle,
          standoff,
          explosive,
          jetVelocityKms: (physics.Vjet / 1000).toFixed(2),
          penetrationMmRha: physics.Peff,
          standoffFactor: (physics.standoffFactor * 100).toFixed(0) + "%",
        })}
        color={T.red}
      />
    </div>
  );
}

import { useState, useRef, useEffect, useMemo, useCallback } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme, prng } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ActionBtn, ResetBtn, ExportBtn, StripChart } from "../components";
import { AIInsight } from "../components/AIInsight";

import { MISSILE_DB } from "../data/missileDB";

export default function SolidRocketSim() {
  const related = MISSILE_DB.filter((m) => m.relatedSimId === "rocket");
  const [burning, setBurning] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [burnRate, setBurnRate] = useState(5);
  const [chamberP, setChamberP] = useState(7);
  const [grain, setGrain] = useState("star");
  const [thrustHistory, setThrustHistory] = useState([]);
  const animRef = useRef(null);
  const startRef = useRef(null);
  const dur = 8;

  const thrust = useMemo(() => {
    const m = grain === "star" ? 1.4 : grain === "tubular" ? 1.0 : 0.6;
    const Cf = 1.3 + 0.05 * (chamberP / 7);
    const At = 0.005;
    return ((Cf * At * chamberP * 1e6 * m) / 1000).toFixed(0);
  }, [chamberP, grain]);

  const cStar = useMemo(() => {
    return Math.round((chamberP * 100) / burnRate);
  }, [chamberP, burnRate]);

  const isp = useMemo(() => {
    const Cf = 1.3 + 0.05 * (chamberP / 7);
    const rawIsp = (Cf * cStar) / 9.81;
    return Math.min(310, Math.max(180, Math.round(rawIsp)));
  }, [chamberP, cStar]);

  const progress = Math.min(elapsed / dur, 1);

  const canvasRef = useCanvas(
    (ctx, W, H, frame) => {
      const p = burning ? progress : 0;

      const canvasTheme = getCanvasTheme();
      const bgGlow = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, W / 2);
      bgGlow.addColorStop(0, `${T.accent}05`);
      bgGlow.addColorStop(1, "transparent");
      ctx.fillStyle = canvasTheme.panelFill;
      ctx.fillRect(0, 0, W, H);
      ctx.fillStyle = bgGlow;
      ctx.fillRect(0, 0, W, H);

      ctx.fillStyle = "#1E3A5F";
      ctx.strokeStyle = `${T.accent}40`;
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.roundRect(40, 30, W - 100, H - 60, 12);
      ctx.fill();
      ctx.stroke();

      ctx.fillStyle = canvasTheme.canvasSurface;
      ctx.beginPath();
      ctx.roundRect(48, 38, W - 116, H - 76, 8);
      ctx.fill();

      const gi = 56 + p * 60,
        gw = Math.max(0, W - 132 - p * 120),
        gh = Math.max(0, H - 92 - p * 40);

      if (gw > 0 && gh > 0) {
        const gr = ctx.createLinearGradient(gi, 0, gi + gw, 0);
        gr.addColorStop(0, "#5a3a1a");
        gr.addColorStop(0.3, "#8B4513");
        gr.addColorStop(0.5, "#A0522D");
        gr.addColorStop(0.7, "#8B4513");
        gr.addColorStop(1, "#5a3a1a");

        ctx.fillStyle = gr;
        ctx.beginPath();
        ctx.roundRect(gi, 46 + p * 20, gw, gh, 6);
        ctx.fill();

        if (burning) {
          ctx.shadowBlur = 15;
          ctx.shadowColor = T.orange;
          ctx.strokeStyle = "rgba(255, 100, 0, 0.5)";
          ctx.lineWidth = 2;
          ctx.stroke();
          ctx.shadowBlur = 0;
        }

        ctx.fillStyle = canvasTheme.canvasSurface;
        const cx = gi + gw / 2,
          cy = 46 + p * 20 + gh / 2;

        if (grain === "star") {
          ctx.beginPath();
          for (let i = 0; i < 5; i++) {
            const a = ((i * 72 - 90) * Math.PI) / 180,
              r = Math.min(gw, gh) * 0.35;
            const x = cx + Math.cos(a) * r;
            const y = cy + Math.sin(a) * r;
            if (i === 0) ctx.moveTo(x, y);
            else ctx.lineTo(x, y);
            const a2 = ((i * 72 - 54) * Math.PI) / 180,
              r2 = r * 0.4;
            ctx.lineTo(cx + Math.cos(a2) * r2, cy + Math.sin(a2) * r2);
          }
          ctx.closePath();
          ctx.fill();
        } else if (grain === "tubular") {
          ctx.beginPath();
          ctx.arc(cx, cy, Math.min(Math.min(gw, gh) * 0.2 + p * 15, gh * 0.45), 0, Math.PI * 2);
          ctx.fill();
        } else {
          ctx.fillRect(gi + gw * (1 - p * 0.55), 46 + p * 20, gw * p * 0.55 + 5, gh);
        }
      }

      ctx.fillStyle = "#2D3748";
      ctx.beginPath();
      ctx.moveTo(W - 60, 40);
      ctx.lineTo(W - 35, H / 2 - 12);
      ctx.lineTo(W - 15, 20);
      ctx.lineTo(W - 15, H - 20);
      ctx.lineTo(W - 35, H / 2 + 12);
      ctx.lineTo(W - 60, H - 40);
      ctx.closePath();
      ctx.fill();

      const nozzleGrad = ctx.createLinearGradient(W - 60, 0, W - 15, 0);
      nozzleGrad.addColorStop(0, "rgba(0,0,0,0.3)");
      nozzleGrad.addColorStop(1, "rgba(255,255,255,0.1)");
      ctx.fillStyle = nozzleGrad;
      ctx.fill();

      if (burning && p < 1) {
        const intensity = Math.max(0, Math.min(1, elapsed / 0.5) * (1 - Math.max(0, (p - 0.9) / 0.1)));
        const flameRadiusX = Math.max(0, 60 * intensity);
        const flameRadiusY = Math.max(0, 10 * intensity);

        if (flameRadiusX > 0 && flameRadiusY > 0) {
          const coreGrad = ctx.createLinearGradient(W - 15, 0, W + 100, 0);
          coreGrad.addColorStop(0, "rgba(255,255,255,0.9)");
          coreGrad.addColorStop(0.2, T.accent);
          coreGrad.addColorStop(1, "transparent");

          ctx.fillStyle = coreGrad;
          ctx.beginPath();
          ctx.ellipse(W - 10, H / 2, flameRadiusX, flameRadiusY, 0, 0, Math.PI * 2);
          ctx.fill();

          for (let i = 0; i < 20; i++) {
            const fl = (50 + prng(frame, i * 5) * 80) * intensity,
              sp = (prng(frame, i * 5 + 1) - 0.5) * 40 * intensity;
            ctx.strokeStyle = i < 8 ? T.white : i < 15 ? T.accent : T.pink;
            ctx.globalAlpha = 0.4 + prng(frame, i * 5 + 2) * 0.4;
            ctx.lineWidth = 1 + prng(frame, i * 5 + 3) * 3;
            ctx.beginPath();
            ctx.moveTo(W - 15, H / 2 + (prng(frame, i * 5 + 4) - 0.5) * 10);
            ctx.lineTo(W - 15 + fl, H / 2 + sp);
            ctx.stroke();
          }
          ctx.globalAlpha = 1;
        }
      }

      ctx.font = `900 10px ${TECH_FONT}`;
      ctx.fillStyle = T.accent;
      ctx.fillText("UNIT-A: COMMAND CASING", 45, 25);
      ctx.fillStyle = T.orange;
      ctx.fillText("MAT: SOLID PROPELLANT", 80, H / 2 - 35);
      ctx.fillStyle = T.gray;
      ctx.font = `600 9px ${TECH_FONT}`;
      ctx.fillText("CD-NOZZLE v2.0", W - 85, 16);

      ctx.shadowBlur = 10;
      ctx.shadowColor = T.red;
      ctx.fillStyle = T.red;
      ctx.beginPath();
      ctx.arc(48, H / 2, 4, 0, Math.PI * 2);
      ctx.fill();
      ctx.shadowBlur = 0;
      ctx.font = `800 8px ${MONO_FONT}`;
      ctx.fillText("IGNITER", 20, H / 2 + 18);

      const burnAreaCurve = Array.from({ length: 40 }, (_, i) => {
        const t = i / 39;
        if (grain === "star") return 1.0 - 0.7 * t;
        if (grain === "tubular") return 0.4 + 0.6 * t;
        return 0.7;
      });
      const stripY = H - 35,
        stripH = 30;
      ctx.fillStyle = "rgba(0,0,0,0.25)";
      ctx.fillRect(5, stripY, W - 10, stripH);
      ctx.strokeStyle = `${T.orange}40`;
      ctx.strokeRect(5, stripY, W - 10, stripH);

      ctx.font = `600 7px ${TECH_FONT}`;
      ctx.fillStyle = T.dimText;
      ctx.textAlign = "left";
      ctx.fillText("Ab", 8, stripY + 9);
      ctx.textAlign = "right";
      ctx.fillText("t→", W - 8, stripY + stripH - 3);

      ctx.strokeStyle = T.orange;
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      burnAreaCurve.forEach((ab, i) => {
        const x = 10 + (i / 39) * (W - 25);
        const y = stripY + stripH - 4 - ab * (stripH - 10);
        i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
      });
      ctx.stroke();

      if (burning) {
        const px = 10 + progress * (W - 25);
        ctx.strokeStyle = T.green;
        ctx.setLineDash([2, 2]);
        ctx.beginPath();
        ctx.moveTo(px, stripY);
        ctx.lineTo(px, stripY + stripH);
        ctx.stroke();
        ctx.setLineDash([]);
      }
    },
    [burning, elapsed, grain, progress],
    { animate: burning },
  );

  useEffect(() => {
    if (!burning) return;
    startRef.current = performance.now();
    const tick = (now) => {
      const dt = (now - startRef.current) / 1000;
      setElapsed(dt);
      if (burning) setThrustHistory((prev) => [...prev.slice(-49), Number(thrust)]);
      if (dt < dur) animRef.current = requestAnimationFrame(tick);
      else {
        setBurning(false);
        setElapsed(dur);
      }
    };
    animRef.current = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(animRef.current);
  }, [burning, thrust]);

  const reset = () => {
    cancelAnimationFrame(animRef.current);
    setBurning(false);
    setElapsed(0);
    setThrustHistory([]);
  };

  const buildPrompt = useCallback(
    () =>
      `Solid rocket motor simulation — current parameters:
ROLE: "You are an expert in solid propulsion. You have deep knowledge of DRDO, HEMRL, and Indian defense R&D programs."

PARAMETERS (numbered):
1. Grain geometry: ${grain} (star/tubular/end-burn)
2. Burn rate: ${burnRate} mm/s
3. Chamber pressure: ${chamberP} MPa
4. Calculated thrust: ${thrust} kN
5. Characteristic velocity (c*): ${cStar} m/s
6. Specific impulse (Isp): ${isp} s
7. Burn progress: ${(progress * 100).toFixed(0)}%

ANALYSIS REQUEST:
Part 1 — PERFORMANCE: Analyze these parameters. Are they realistic? What performance regime do they represent (low/medium/high)? What is the efficiency?
Part 2 — SAFETY & RISK: What are the safety margins? What failure modes exist at these conditions? What would a test engineer watch for?
Part 3 — INDIA-SPECIFIC CONTEXT: How does this relate to DRDO/HEMRL programs? Reference specific Indian systems (e.g., Agni, BrahMos, Pinaka, SMART, Astra, Nag, Akash) where applicable. What are India's current capabilities and gaps in this domain?
Related Indian systems: ${related.map((m) => m.name).join(", ")}`,
    [grain, burnRate, chamberP, thrust, isp, cStar, progress, related],
  );

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={460} height={220} maxWidth={460} />
      <PillRow>
        <Pill
          active={grain === "star"}
          onClick={() => {
            reset();
            setGrain("star");
          }}
        >
          ★ Star
        </Pill>
        <Pill
          active={grain === "tubular"}
          onClick={() => {
            reset();
            setGrain("tubular");
          }}
        >
          ◯ Tubular
        </Pill>
        <Pill
          active={grain === "endburn"}
          onClick={() => {
            reset();
            setGrain("endburn");
          }}
        >
          ▮ End-Burn
        </Pill>
      </PillRow>
      <Slider
        label="Burn Rate"
        value={burnRate}
        onChange={(v) => {
          reset();
          setBurnRate(v);
        }}
        min={2}
        max={12}
        step={0.5}
        unit=" mm/s"
        color={T.orange}
      />
      <Slider
        label="Chamber Pressure"
        value={chamberP}
        onChange={(v) => {
          reset();
          setChamberP(v);
        }}
        min={3}
        max={20}
        step={0.5}
        unit=" MPa"
        color={T.accent}
      />
      <DataRow>
        <DataBox label="Thrust" value={thrust} unit="kN" color={T.orange} />
        <DataBox label="Isp" value={isp} unit="s" color={T.accent} />
        <DataBox label="c*" value={cStar} unit="m/s" color={T.purple} />
        <DataBox label="Burn" value={`${(progress * 100).toFixed(0)}%`} color={burning ? T.green : T.gray} />
      </DataRow>
      <StripChart data={thrustHistory} color={T.orange} label="Thrust (kN)" maxVal={Number(thrust) * 1.5 || 100} />
      <div style={{ display: "flex", gap: 8 }}>
        <ActionBtn
          onClick={() => {
            if (!burning) {
              setElapsed(0);
              setBurning(true);
            }
          }}
          disabled={burning}
          color={T.red}
        >
          {burning ? "BURNING..." : progress >= 1 ? "BURNOUT" : "🔥 IGNITE"}
        </ActionBtn>
        <ResetBtn onClick={reset} />
      </div>
      <InfoBox color={T.accent}>
        <strong style={{ color: T.accent }}>How it works:</strong> Solid propellant burns inward from grain bore.
        {grain === "star"
          ? " Star bore → high initial thrust, regressive."
          : grain === "tubular"
            ? " Tubular bore → progressive thrust increase."
            : " End-burn → long, constant low thrust."}{" "}
        Gas exits convergent-divergent nozzle → thrust (Newton's 3rd).
        {related.length > 0 && (
          <div style={{ marginTop: 8, borderTop: `1px solid ${T.glassBorder}`, paddingTop: 8 }}>
            <div style={{ fontSize: 10, fontWeight: 700, color: T.accent, marginBottom: 4 }}>
              INDIAN SYSTEMS USING THIS TECHNOLOGY:
            </div>
            {related.map((m) => (
              <div key={m.id} style={{ fontSize: 10, color: T.gray, marginBottom: 2 }}>
                {m.image_emoji} <strong style={{ color: T.white }}>{m.name}</strong>
                {" — "}{m.propulsion.stages} | {m.performance.range}
                {m.sources[0] && (
                  <a href={m.sources[0].url} target="_blank" rel="noopener noreferrer"
                     style={{ color: T.accent, marginLeft: 4, fontSize: 9 }}>
                    [source]
                  </a>
                )}
              </div>
            ))}
          </div>
        )}
      </InfoBox>
      <AIInsight buildPrompt={buildPrompt} color={T.orange} />
      <ExportBtn simId="rocket" getData={() => ({ grain, burnRate, chamberP, thrust, isp })} color={T.orange} />
    </div>
  );
}

import { useState, useCallback, useMemo } from "react";
import { T, TECH_FONT, MONO_FONT, useCanvas, getCanvasTheme } from "../utils";
import { Pill, PillRow, Slider, DataBox, DataRow, InfoBox, SimCanvas, ExportBtn } from "../components";
import { AIInsight } from "../components/AIInsight";

export default function WaterRamjetSim() {
  const [fuel, setFuel] = useState("mg_ptfe");
  const [cruiseSpeed, setCruiseSpeed] = useState(100);
  const [waterRatio, setWaterRatio] = useState(1.5);
  const [depth, setDepth] = useState(50);
  const [running, setRunning] = useState(true);

  // Fuel properties
  const fuelData = {
    mg_ptfe:      { energy: 24.7, density: 1.85, tFlame: 2800, ignDelay: 0.8, label: "Mg/PTFE" },
    al_polyester: { energy: 31.0, density: 2.10, tFlame: 3200, ignDelay: 2.5, label: "Al/Polyester" },
    mg_al_mix:    { energy: 27.5, density: 1.95, tFlame: 3000, ignDelay: 1.2, label: "Mg-Al Mix" },
    li_hydride:   { energy: 43.0, density: 0.92, tFlame: 2600, ignDelay: 3.0, label: "LiAlH₄" },
  };
  const fd = a => fuelData[a] || fuelData.mg_ptfe;
  const currentFd = fd(fuel);

  // Stagnation (ram) pressure from cruise speed
  const rhoWater = 1025; // kg/m³ seawater
  const pStag = 0.5 * rhoWater * cruiseSpeed * cruiseSpeed; // Pa
  const pStagMPa = (pStag / 1e6).toFixed(2);

  // Hydrostatic back-pressure from depth
  const pDepth = rhoWater * 9.81 * depth; // Pa
  const pDepthMPa = (pDepth / 1e6).toFixed(2);

  // Net chamber pressure
  const pChamber = Math.max(0, pStag - pDepth);
  const pChamberMPa = (pChamber / 1e6).toFixed(2);
  const canOperate = pChamber > 100000 && running;

  // Combustion temperature
  const optimalWP = fuel === "al_polyester" ? 1.0 : fuel === "li_hydride" ? 0.8 : 1.5;
  const wpEfficiency = 1 - 0.25 * Math.pow(waterRatio - optimalWP, 2);
  const Tcomb = Math.round(currentFd.tFlame * Math.max(0.3, Math.min(1.0, wpEfficiency)));

  // Specific impulse
  const eta = canOperate ? Math.min(0.85, 0.4 + pChamberMPa * 0.08) : 0;
  const Ve = Math.sqrt(2 * 1500 * Tcomb * eta); // exhaust velocity
  const isp = canOperate ? Math.round(Ve / 9.81) : 0;

  // Thrust
  const mdotProp = 0.5; // kg/s
  const mdotTotal = mdotProp * (1 + waterRatio);
  const thrust = canOperate ? Math.max(0, Math.round((mdotTotal * Ve - mdotTotal * cruiseSpeed) / 1000 * 10) / 10) : 0; // kN

  // Density-specific impulse
  const rhoIsp = Math.round(isp * currentFd.density);

  // Speed regime label
  const regime = cruiseSpeed < 40 ? "CONVENTIONAL" :
                 cruiseSpeed < 80 ? "HIGH SPEED" :
                 cruiseSpeed < 120 ? "SUPERCAVITATING" : "HYPERCAVITATING";

  const regimeColor = cruiseSpeed < 40 ? T.green : cruiseSpeed < 80 ? T.gold : cruiseSpeed < 120 ? T.orange : T.red;

  const canvasRef = useCanvas((ctx, W, H, frame) => {
    const cy = H / 2;
    const theme = getCanvasTheme();

    // Background
    ctx.fillStyle = theme.canvasBackground;
    ctx.fillRect(0, 0, W, H);
    // Slight blue tint for underwater effect
    ctx.fillStyle = "rgba(0, 50, 100, 0.1)";
    ctx.fillRect(0, 0, W, H);

    // Torpedo Body
    const tLength = 200;
    const tHeight = 40;
    const tx = W / 2 - tLength / 2;
    const ty = cy - tHeight / 2;

    // Core body metallic gray
    ctx.fillStyle = "#A0AEC0";
    ctx.beginPath();
    ctx.roundRect(tx, ty, tLength, tHeight, 4);
    ctx.fill();

    // Nose Cone
    ctx.beginPath();
    ctx.moveTo(tx, ty);
    if (cruiseSpeed > 80) {
      // Cavitator disc
      ctx.lineTo(tx - 10, ty + tHeight / 2);
    } else {
      ctx.lineTo(tx - 30, ty + tHeight / 2);
    }
    ctx.lineTo(tx, ty + tHeight);
    ctx.fill();

    // Water Inlets
    ctx.fillStyle = T.accent;
    ctx.fillRect(tx + 20, ty - 5, 20, 10);
    ctx.fillRect(tx + 20, ty + tHeight - 5, 20, 10);

    // Combustion Chamber Inner Wall
    const cbX = tx + 80;
    const cbW = 70;
    ctx.fillStyle = "#1A202C";
    ctx.fillRect(cbX, ty + 5, cbW, tHeight - 10);

    // Fuel Grain Liner
    const fColor = fuel === "mg_ptfe" ? "#A0AEC0" : fuel === "al_polyester" ? "#D6BCFA" : fuel === "mg_al_mix" ? "#F6E05E" : "#9AE6B4";
    ctx.fillStyle = fColor;
    ctx.fillRect(cbX, ty + 5, cbW, 5);
    ctx.fillRect(cbX, ty + tHeight - 10, cbW, 5);

    // Combustion Glow
    if (canOperate) {
        const glow = ctx.createLinearGradient(cbX, 0, cbX + cbW, 0);
        const mainColor = Tcomb > 3000 ? T.white : Tcomb > 2000 ? T.gold : T.orange;
        glow.addColorStop(0, "rgba(255,255,255,0.1)");
        glow.addColorStop(0.5, mainColor);
        glow.addColorStop(1, T.red);
        ctx.fillStyle = glow;
        ctx.fillRect(cbX + 10, ty + 10, cbW - 10, tHeight - 20);
    }

    // Nozzle
    ctx.fillStyle = "#4A5568";
    ctx.beginPath();
    ctx.moveTo(tx + tLength, ty + 5);
    ctx.lineTo(tx + tLength + 20, ty - 5);
    ctx.lineTo(tx + tLength + 20, ty + tHeight + 5);
    ctx.lineTo(tx + tLength, ty + tHeight - 5);
    ctx.fill();

    // Flow Animation
    // Water Ingestion
    ctx.fillStyle = T.cyan;
    for (let i = 0; i < cruiseSpeed / 10; i++) {
        const px = tx - 50 + ((frame * cruiseSpeed * 0.02 + i * 20) % 100);
        ctx.beginPath();
        ctx.arc(px, ty - 8 + Math.sin(px * 0.1) * 2, 1.5, 0, Math.PI*2);
        ctx.arc(px, ty + tHeight + 8 + Math.sin(px * 0.1) * 2, 1.5, 0, Math.PI*2);
        ctx.fill();
    }

    // Exhaust
    if (canOperate) {
        for (let i = 0; i < 30; i++) {
            const exX = tx + tLength + 20 + ((frame * Ve * 0.005 + i * 10) % 150);
            const spread = (exX - (tx + tLength + 20)) * 0.2;
            const exY = cy + (Math.random() - 0.5) * Math.max(1, spread * 2);
            ctx.fillStyle = i % 2 === 0 ? "rgba(255,255,255,0.4)" : fColor + "80"; // Steam + gas mix
            ctx.beginPath();
            ctx.arc(exX, exY, 2 + Math.random() * 3, 0, Math.PI*2);
            ctx.fill();
        }
    } else {
        // Red X on inlets
        ctx.strokeStyle = T.red;
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(tx + 20, ty - 10); ctx.lineTo(tx + 40, ty + 5);
        ctx.moveTo(tx + 40, ty - 10); ctx.lineTo(tx + 20, ty + 5);
        ctx.stroke();

        ctx.font = `800 10px ${TECH_FONT}`;
        ctx.fillStyle = T.red;
        ctx.textAlign = "center";
        ctx.fillText("INSUFFICIENT RAM PRESSURE", W / 2, cy + 40);
        ctx.textAlign = "left";
    }

    // Supercavitation Envelope
    if (cruiseSpeed > 80) {
        ctx.strokeStyle = "rgba(255, 255, 255, 0.3)";
        ctx.lineWidth = 2;
        ctx.setLineDash([5, 5]);
        ctx.beginPath();
        ctx.ellipse(tx + tLength / 2, cy, tLength * 0.6, tHeight * 1.5, 0, 0, Math.PI * 2);
        ctx.stroke();
        ctx.setLineDash([]);

        ctx.font = `800 8px ${MONO_FONT}`;
        ctx.fillStyle = "rgba(255, 255, 255, 0.5)";
        ctx.textAlign = "center";
        ctx.fillText("SUPERCAVITATION ENVELOPE", W / 2, cy - tHeight * 1.2);
        ctx.textAlign = "left";
    }

    // Depth Indicator (Right side)
    const dX = W - 20;
    const dY = 10;
    const dH = H - 45;
    const depthGrad = ctx.createLinearGradient(0, dY, 0, dY + dH);
    depthGrad.addColorStop(0, T.cyan);
    depthGrad.addColorStop(1, "#001a33");
    ctx.fillStyle = depthGrad;
    ctx.fillRect(dX, dY, 10, dH);

    // Depth marker
    const markerY = dY + (depth / 200) * dH;
    ctx.fillStyle = T.white;
    ctx.beginPath();
    ctx.moveTo(dX - 5, markerY);
    ctx.lineTo(dX, markerY - 3);
    ctx.lineTo(dX, markerY + 3);
    ctx.fill();

    // Bottom info strip
    ctx.fillStyle = "rgba(0,0,0,0.5)";
    ctx.fillRect(0, H - 25, W, 25);
    ctx.fillStyle = regimeColor;
    ctx.font = `800 10px ${TECH_FONT}`;
    ctx.textAlign = "center";
    ctx.fillText(`${regime} REGIME (${cruiseSpeed} m/s)`, W / 2, H - 8);
    ctx.textAlign = "left";

  }, [cruiseSpeed, depth, fuel, waterRatio, canOperate, Tcomb, Ve, regime, regimeColor], { animate: true });

  const buildPrompt = useCallback(() =>
    `You are an expert in underwater water-breathing ramjet propulsion and hydro-reactive metal fuel combustion.

PARAMETERS:
- Fuel: ${currentFd.label} (Energy: ${currentFd.energy} MJ/kg, Density: ${currentFd.density} g/cc)
- Cruise Speed: ${cruiseSpeed} m/s (${regime})
- Water-to-Propellant Ratio (W/P): ${waterRatio.toFixed(1)} (Optimal: ${optimalWP})
- Depth: ${depth} m
- Operating Status: ${canOperate ? "ACTIVE" : "INSUFFICIENT RAM PRESSURE"}
- Net Ram Pressure: ${pChamberMPa} MPa
- Combustion Temp: ${Tcomb} K
- Specific Impulse (Isp): ${isp} s
- Density Isp: ${rhoIsp} kg.s/m³
- Net Thrust: ${thrust} kN

ANALYSIS REQUEST:
Please evaluate the vehicle performance at these conditions. Include in prompt: "Reference: FA01-P10 (HEMCE 2026), Eisen & Gany (Technion) water-breathing ramjet research, Shkval torpedo Mg-based propulsion". Discuss the feasibility of sustained operation at the current depth and speed, and how the selected fuel influences the energy density compared to conventional thermal propulsion systems.`,
  [currentFd, cruiseSpeed, regime, waterRatio, optimalWP, depth, canOperate, pChamberMPa, Tcomb, isp, rhoIsp, thrust]);

  return (
    <div>
      <SimCanvas canvasRef={canvasRef} width={370} height={150} maxWidth={370} />

      <PillRow>
        <Pill active={fuel === "mg_ptfe"} onClick={() => setFuel("mg_ptfe")} color={T.gray}>Mg/PTFE</Pill>
        <Pill active={fuel === "al_polyester"} onClick={() => setFuel("al_polyester")} color={T.purple}>Al/Poly</Pill>
        <Pill active={fuel === "mg_al_mix"} onClick={() => setFuel("mg_al_mix")} color={T.gold}>Mg-Al Mix</Pill>
        <Pill active={fuel === "li_hydride"} onClick={() => setFuel("li_hydride")} color={T.green}>LiAlH₄</Pill>
        <Pill active={running} onClick={() => setRunning(!running)} color={running ? T.red : T.green}>{running ? "⏹ Stop" : "▶ Run"}</Pill>
      </PillRow>

      <Slider label="Cruise Speed" value={cruiseSpeed} onChange={setCruiseSpeed} min={20} max={150} unit="m/s" color={T.cyan} />
      <Slider label="Water/Fuel (W/P)" value={waterRatio} onChange={setWaterRatio} min={0.5} max={4.0} step={0.1} unit="" color={T.accent} />
      <Slider label="Depth" value={depth} onChange={setDepth} min={5} max={200} unit="m" color="#004488" />

      <DataRow>
        <DataBox label="Isp" value={canOperate ? isp : "—"} unit="s" color={T.accent} />
        <DataBox label="ρIsp" value={rhoIsp} unit="kg·s/m³" color={T.purple} />
        <DataBox label="Thrust" value={thrust.toFixed(1)} unit="kN" color={T.orange} />
        <DataBox label="P_ram" value={pStagMPa} unit="MPa" color={T.cyan} />
        <DataBox label="Tcomb" value={Tcomb} unit="K" color={Tcomb > 3000 ? T.white : Tcomb > 2000 ? T.gold : T.orange} />
        <DataBox label="Regime" value={regime} unit="" color={regimeColor} />
      </DataRow>

      {!canOperate ? (
        <div style={{ textAlign: "center", fontSize: 11, fontWeight: 700, color: T.red, fontFamily: TECH_FONT, margin: "8px 0" }}>
          ⚠ CANNOT OPERATE — Ram pressure ({pStagMPa} MPa) &lt; depth pressure ({pDepthMPa} MPa). Increase speed or decrease depth.
        </div>
      ) : (
        <div style={{ textAlign: "center", fontSize: 10, color: T.dimText, fontFamily: TECH_FONT, margin: "8px 0" }}>
          Optimal W/P for {currentFd.label}: {optimalWP} — Current: {waterRatio.toFixed(1)}
          {Math.abs(waterRatio - optimalWP) > 0.8 ? " ⚠ Far from optimal" : " ✓ Near optimal"}
        </div>
      )}

      <InfoBox>
        Water-breathing ramjets use seawater as both working fluid and oxidizer for hydro-reactive metal fuels (Mg, Al). At 100 m/s cruise, ram pressure reaches 5 MPa — enough to force seawater into the combustor without pumps. Achieved Isp of 485s (2× solid rockets). Russia's Shkval torpedo (200+ knots) uses Mg-based hydroreactive fuel. DRDO's SMART system and Varunastra torpedo programs are exploring advanced underwater propulsion. Paper FA01-P10 at HEMCE 2026 presents variable-thrust water-breathing engine research.
      </InfoBox>

      <AIInsight buildPrompt={buildPrompt} color={T.cyan} />
      <ExportBtn simId="waterjet" getData={() => ({ fuel, cruiseSpeed, waterRatio, depth, isp, thrust })} color={T.cyan} />
    </div>
  );
}

